// 生成物: scripts/whisky_build.py（産地エリアパック統合）
window.WCQ_AREAS = {"areas":[{"id":"scotland","name":"スコットランド","tagline":"モルトの聖地、密造の霧から世界へ","background":"北緯55度から59度、大西洋とその支流が刻む荒々しい丘陵と泥炭地。スコットランドの気候と地質は、そのままウイスキーの個性となった。清冽な湧水、豊富な大麦、そして燃料として掘られたピート(泥炭)は、蒸留という営みをこの土地に深く根付かせた。\n\n蒸留技術がいつこの地に伝わったかは定かではないが、1494年の財務省記録には修道士ジョン・コーへ麦芽を渡した記載が残る。宗教改革で修道院が解体されると、蒸留の技は民間へ広がり、やがて課税の対象となった。重税は密造を生み、ハイランドの谷間には煙を隠す蒸留器が数百と潜んだと伝わる。\n\n1823年の酒税法改正は密造者を合法な蒸留業者へと導いた。グレンリベットの公認、連続式蒸留機の発明によるグレーンウイスキーの量産は、ブレンデッドウイスキーという新たな産業を生んだ。折しもフランスをブドウの害虫フィロキセラが襲い、ブランデーが市場を失うと、スコッチはその空白を埋めて世界へ躍進した。\n\nしかし栄光は続かなかった。1898年のパティソン破綻、二度の大戦、世界恐慌は業界を疲弊させ、1980年代には需要低迷で数十の蒸留所が閉鎖に追い込まれた。\n\nそれでも土地の記憶は絶えなかった。1963年にグレンフィディックが先駆けたシングルモルトの魅力は、やがて世界的なブームとなり、閉鎖された蒸留所の再興や新設のクラフト蒸留所が相次いだ。密造の霧から出発したこの土地は、いまやモルトの聖地として世界中の愛好家を迎えている。","timeline":[{"year":1494,"era":"origins","icon":"scroll","title":"最古の記録","text":"スコットランド財務省の記録に、修道士ジョン・コーへ麦芽八ボルを渡し『生命の水』を造らせたとの記載が残る。文献上確認できる最古のスコッチ蒸留の証拠である。"},{"year":1560,"era":"origins","icon":"still","title":"修道院からの蒸留技術","text":"宗教改革で修道院が解体されると、蒸留の知識を持つ修道士たちが各地へ散り、蒸留技術は農家や領主のもとで民間に広く伝わっていった。"},{"year":1644,"era":"origins","icon":"law","title":"最初の酒税","text":"スコットランド議会がモルト酒への物品税を初めて導入した。以後たびたび税率が引き上げられ、密造と脱税の温床を生む出発点となった。"},{"year":1707,"era":"smuggling","icon":"crown","title":"合同法とイングランド市場","text":"スコットランドとイングランドが合同法で一つの王国となり、市場は広がったものの、より厳格な酒税制度が導入され密造がいっそう拡大した。"},{"year":1784,"era":"smuggling","icon":"law","title":"ハイランドラインの設定","text":"ウォッシュ法によりハイランドとローランドで税率や規制が分けられ、境界線『ハイランドライン』が引かれた。以後密造の黄金時代が続いたと伝わる。"},{"year":1823,"era":"industrial","icon":"law","title":"酒税法改正","text":"エクサイズ法(酒税法)の改正で低額の免許料により合法な蒸留が可能となり、密造者たちが次々と正規の蒸留所経営へ転じていった。"},{"year":1824,"era":"industrial","icon":"factory","title":"グレンリベットの公認","text":"密造の本場グレンリベットで、ジョージ・スミスが新法下いち早く蒸留免許を取得した。近隣の密造者の反発を受けながらも合法蒸留の先駆けとなった。"},{"year":1830,"era":"industrial","icon":"still","title":"連続式蒸留機の登場","text":"イーニアス・コフィーが特許を得た連続式蒸留機により、安価なグレーンウイスキーの大量生産が可能となり、後のブレンデッド全盛期を準備した。"},{"year":1860,"era":"industrial","icon":"law","title":"スピリッツ法とブレンデッドの誕生","text":"スピリッツ法によりモルトとグレーンの原酒を同一保税倉庫で混和することが認められ、まろやかで飲みやすいブレンデッドウイスキーが誕生した。"},{"year":1880,"era":"industrial","icon":"globe","title":"フィロキセラ禍とスコッチの躍進","text":"ブドウの害虫フィロキセラがフランスのブドウ畑を壊滅させブランデー生産が激減すると、スコッチウイスキーがその代替として世界市場へ躍進した。"},{"year":1895,"era":"industrial","icon":"trophy","title":"ブレンデッドの巨人たち","text":"デュワーズ、ジョニーウォーカー、ブキャナンといったブレンド業者が海外市場を開拓し、スコッチウイスキーの名を世界中に知らしめていった。"},{"year":1898,"era":"industrial","icon":"fire","title":"パティソン破綻","text":"急成長していたパティソン社が粗悪な増量ウイスキーの発覚とともに破綻した。業界全体の信用が揺らぎ、多くの蒸留所が連鎖倒産に追い込まれた。"},{"year":1925,"era":"crisis","icon":"factory","title":"DCLへの統合","text":"経営難の蒸留所や企業が相次いでディスティラーズ・カンパニー・リミテッド(DCL)へ統合され、業界の寡占化と大規模生産体制が進んだ。"},{"year":1933,"era":"crisis","icon":"fire","title":"世界恐慌と閉鎖の時代","text":"アメリカの禁酒法と世界恐慌により輸出が落ち込み、多くの蒸留所が長期休止や閉鎖に追い込まれる、業界にとって最も厳しい時代を迎えた。"},{"year":1963,"era":"crisis","icon":"glass","title":"シングルモルトへの先駆","text":"グレンフィディックが他社に先駆けてシングルモルトを単独銘柄として海外へ積極的に売り出し、後のシングルモルトブームの礎を築いた。"},{"year":1983,"era":"renaissance","icon":"fire","title":"ウイスキーローホと大量閉鎖","text":"需要低迷と過剰在庫を背景に、1980年代前半だけで多くの蒸留所が操業停止に追い込まれ、業界は『ウイスキーローホ』と呼ばれる不況に沈んだ。"},{"year":2000,"era":"renaissance","icon":"trophy","title":"シングルモルトブーム","text":"1990年代以降、個性を重視するシングルモルトの人気が世界的に高まり、休止蒸留所の再稼働や熟成古酒の評価向上が相次いで起きた。"},{"year":2013,"era":"renaissance","icon":"factory","title":"クラフト蒸留所の勃興","text":"規制緩和や需要拡大を背景に新設の小規模蒸留所が各地で相次いで誕生し、伝統産地に新たな個性と多様性をもたらす動きが続いている。"}],"distilleries":[{"id":"macallan","name":"マッカラン","en":"The Macallan","lat":57.48,"lon":-3.21,"region":"scotland-speyside","founded":1824,"history":"1824年、アレクサンダー・リードがスペイ川畔の丘に創業免許を得た。シェリー樽での熟成に強くこだわる方針を早くから掲げ、その品質は今日まで受け継がれている。20世紀後半にシングルモルトとして高い評価を確立し、近年は稀少な古酒がオークションで高額落札されることでも知られる、スコッチ最高峰の一角である。","bottles":["マッカラン12年 シェリーオークカスク","マッカラン12年 ダブルカスク","マッカラン18年 シェリーオークカスク","マッカラン ファインオーク15年"],"trivia":"シェリー樽熟成へのこだわりから、かつては原酒のほとんどをシェリー樽で熟成させていたと伝わる。現在もスペインの樽職人と長期契約を結び、専用に仕立てたオロロソシェリー樽を毎年発注していると言われる。","tags":["macallan","sherry-cask","speyside"]},{"id":"glenfiddich","name":"グレンフィディック","en":"Glenfiddich","lat":57.44,"lon":-3.13,"region":"scotland-speyside","founded":1887,"history":"1887年、ウィリアム・グラントが家族と共に石を積み、手作りで蒸留所を建てたと伝わる。1963年、他社に先駆けてシングルモルトを単独銘柄として海外市場へ積極的に売り出し、今日世界中で楽しまれているシングルモルトブームの礎を築いた先駆者として知られる。現在も創業家グラント家が経営を続ける数少ない大手蒸留所の一つである。","bottles":["グレンフィディック12年","グレンフィディック15年 ソレラリザーブ","グレンフィディック18年","グレンフィディック21年 グランレゼルバ"],"trivia":"蒸留所名は『鹿の谷』を意味するゲール語に由来し、ラベルに描かれた金色の鹿はそこから採られている。創業者一族による経営は5代以上にわたり続いており、非上場のまま独立を保つ稀有な存在でもある。","tags":["glenfiddich","speyside","single-malt-pioneer"]},{"id":"glenlivet","name":"ザ・グレンリベット","en":"The Glenlivet","lat":57.35,"lon":-3.24,"region":"scotland-speyside","founded":1824,"history":"18世紀から密造の中心地だったグレンリベットの谷で、ジョージ・スミスは1824年、酒税法改正後いち早く合法の蒸留免許を取得した。裏切り者と見なされ近隣の密造者から命を狙われ、護身用の拳銃を携えていたとも伝わるが、その丁寧な仕込みは評価を集め続け、後年『ザ・グレンリベット』の名を法的に独占する特別な地位を築くに至った。","bottles":["ザ・グレンリベット12年","ザ・グレンリベット15年 フレンチオークリザーブ","ザ・グレンリベット18年","ザ・グレンリベット ナデューラ"],"trivia":"19世紀後半、多くの近隣蒸留所が『グレンリベット』を名乗ろうとしたため、訴訟の末に『The』を冠する正式名称の使用権を法的に勝ち取った。以来この一語は同蒸留所だけの特別な称号として扱われている。","tags":["glenlivet","speyside","legal-pioneer"]},{"id":"balvenie","name":"バルヴェニー","en":"The Balvenie","lat":57.44,"lon":-3.14,"region":"scotland-speyside","founded":1892,"history":"1892年、グレンフィディックの創業者ウィリアム・グラントが隣接地に建てた姉妹蒸留所である。大麦の自家製麦、専属の樽職人や銅細工師を自社で抱える伝統的な製法を今も守り続けており、大規模化が進んだ現代のスコッチ業界では珍しい存在となった。少量生産ながら熟練職人の技が光る、複雑で豊かな個性を持つ原酒を生み出している。","bottles":["バルヴェニー12年 ダブルウッド","バルヴェニー14年 カリビアンカスク","バルヴェニー17年 ダブルウッド","バルヴェニー21年 ポートウッド"],"trivia":"敷地内に自前のフロアモルティングと製樽所を保有する数少ない蒸留所で、モルトマンが木製シャベルで麦芽を返す手仕事や、樽職人が火であぶり樽を組む様子を今も見学できる。","tags":["balvenie","speyside","floor-malting"]},{"id":"glenfarclas","name":"グレンファークラス","en":"Glenfarclas","lat":57.38,"lon":-3.28,"region":"scotland-speyside","founded":1836,"history":"1836年創業、1865年からグラント家が所有し続ける独立系の家族経営蒸留所である。20世紀に周辺の多くの蒸留所が大手資本に統合されていく中でも一族経営を貫き通し、シェリー樽熟成にこだわった重厚で力強い原酒を長年供給し続けている。加水を抑えた高めのアルコール度数で瓶詰めする姿勢も一貫して守られている。","bottles":["グレンファークラス10年","グレンファークラス12年","グレンファークラス15年","グレンファークラス105(カスクストレングス)"],"trivia":"1865年の買収以来150年以上にわたりグラント家が経営を続ける、スコットランドで最も古い独立家族経営蒸留所の一つである。歴代当主の肖像がラベルやボトルに描かれている。","tags":["glenfarclas","speyside","family-owned"]},{"id":"ardbeg","name":"アードベグ","en":"Ardbeg","lat":55.64,"lon":-6.11,"region":"scotland-islay","founded":1815,"history":"1815年創業、アイラ島南岸の切り立った崖のそばに位置し、島の中でも屈指の強烈なピート香で知られる。業界不況のあおりを受けて20世紀後半に一時操業停止に追い込まれたが、1997年にグレンモーレンジィ社が買収して設備を刷新し復活を遂げた。以来、熱狂的なファンコミュニティ『アードベグ委員会』を持つことでも有名な銘柄へと成長している。","bottles":["アードベグ10年","アードベグ ウーガダール","アードベグ コリーヴレッカン","アードベグ アン・オー"],"trivia":"世界中に数十万人の会員を持つファンクラブ『アードベグ委員会』があり、毎年限定ボトルの投票やアードベグの日と呼ばれる祝祭イベントが世界各地の支部で盛大に開催される。","tags":["ardbeg","islay","peated"]},{"id":"lagavulin","name":"ラガヴーリン","en":"Lagavulin","lat":55.63,"lon":-6.13,"region":"scotland-islay","founded":1816,"history":"1816年創業(それ以前から複数の小規模な密造蒸留所が同じ入江にひしめいていたと伝わる)、アイラ島南岸の小さな湾に建つ。極端に長時間かけたゆっくりとした蒸留で生まれる濃厚な潮の香りと強いピート香を特徴とし、ディアジオ社が展開するクラシックモルトシリーズの看板銘柄として、アイラモルトの代表格に数えられるほどの世界的な知名度を持つに至った。","bottles":["ラガヴーリン16年","ラガヴーリン8年","ラガヴーリン ディスティラーズエディション","ラガヴーリン12年 カスクストレングス"],"trivia":"米国の人気テレビドラマの登場人物が愛飲する銘柄として作中で繰り返し描かれたことがきっかけとなり、それまでウイスキーに馴染みのなかった若い世代にも一躍知名度が上がった逸話がある。","tags":["lagavulin","islay","peated"]},{"id":"laphroaig","name":"ラフロイグ","en":"Laphroaig","lat":55.63,"lon":-6.15,"region":"scotland-islay","founded":1815,"history":"1815年創業、アイラ島の海辺に建つ。自家製麦で用いる地元産ピートを豊富に焚き込み、消毒薬や正露丸を思わせるとも評される強烈な薬品香は好みが大きく分かれるが、それゆえに世界中に根強い熱狂的なファンを持つ個性派として知られる。英国王室御用達の認証(ロイヤルワラント)を受けた稀有なアイラ島の蒸留所でもある。","bottles":["ラフロイグ10年","ラフロイグ クオーターカスク","ラフロイグ10年 カスクストレングス","ラフロイグ セレクト"],"trivia":"当時のチャールズ皇太子が蒸留所を訪れ強烈な個性のこの酒を大変気に入り愛飲したことがきっかけで王室御用達の認証を受け、以来ラベルにも王室紋章が誇らしげに描かれ続けている。","tags":["laphroaig","islay","peated"]},{"id":"bowmore","name":"ボウモア","en":"Bowmore","lat":55.76,"lon":-6.29,"region":"scotland-islay","founded":1779,"history":"1779年創業、現存するアイラ島最古の蒸留所とされる。島の中心地ボウモアの海沿いに位置し、満潮時には貯蔵庫の一部が海面下になることでも知られる、潮の満ち引きと共に生きてきた蒸留所である。過度に主張しすぎないバランスの取れたピート香と、湿った潮の風味を併せ持つ原酒を、長い年月をかけて安定して生み出し続けている老舗である。","bottles":["ボウモア12年","ボウモア15年 ダーケストシェリーカスク","ボウモア18年","ボウモア スモールバッチ"],"trivia":"貯蔵庫の一部『No.1ヴォールツ』は海面より低い位置にあり、スコットランド最古の熟成庫の一つとして知られる。壁越しに波音が絶え間なく響くとも言われ、原酒はその音を聞きながら静かに眠っている。","tags":["bowmore","islay","peated"]},{"id":"springbank","name":"スプリングバンク","en":"Springbank","lat":55.42,"lon":-5.6,"region":"scotland-campbeltown","founded":1828,"history":"1828年創業、かつて30以上の蒸留所が密集し『ウイスキーの首都』とまで呼ばれ栄えたキャンベルタウンで、20世紀の相次ぐ閉鎖の波を乗り越えて生き残った数少ない存在である。製麦から蒸留、熟成、瓶詰めまで全工程を自社敷地内で行う稀有な蒸留所として知られ、創業家の血を引く独立系のミッチェル家が代々経営を続けている。","bottles":["スプリングバンク10年","スプリングバンク15年","スプリングバンクCV","ハザバーン10年"],"trivia":"大麦の製麦から蒸留、熟成、瓶詰めまですべての工程を一箇所で完結させる、スコットランドでも数少ない完全一貫生産の蒸留所である。同じ敷地でピートの効き方が異なる複数の原酒を造り分けている。","tags":["springbank","campbeltown","family-owned"]},{"id":"talisker","name":"タリスカー","en":"Talisker","lat":57.3,"lon":-6.36,"region":"scotland-islands","founded":1830,"history":"1830年、荒々しい山と海に囲まれたスカイ島西岸のカーボストに創業した。長らく島唯一の蒸留所として知られ、潮風とピートが融合した力強くスパイシーな味わいが特徴である。特徴的な部分三回蒸留の名残を持つ蒸留器の形状も個性を生み出す一因とされ、ディアジオ社のクラシックモルトシリーズの代表銘柄として親しまれている。","bottles":["タリスカー10年","タリスカー スカイ","タリスカー18年","タリスカー ストーム"],"trivia":"作家ロバート・ルイス・スティーヴンソンが自著の詩でその力強い味わいを称賛したと伝わる、長らくスカイ島唯一の蒸留所であった存在で、島の荒天と潮風がそのまま個性に映し出されている。","tags":["talisker","islands","skye"]},{"id":"highland-park","name":"ハイランドパーク","en":"Highland Park","lat":58.97,"lon":-2.96,"region":"scotland-islands","founded":1798,"history":"1798年創業、スコットランド本土から遠く離れたオークニー諸島カークウォールに位置する、世界最北級の蒸留所の一つである。自家製麦の際に地元産の香り高いピートを用い、シェリー樽での長期熟成による蜂蜜のような甘みと上品なスモークの調和が特徴とされ、業界内外の評論家から長年にわたり高い評価を得続けている名門である。","bottles":["ハイランドパーク12年","ハイランドパーク18年","ハイランドパーク ヴァルハラコレクション","ハイランドパーク15年"],"trivia":"ヴァイキングの歴史が色濃く残るオークニー諸島にあり、ボトルのデザインや商品名の多くに北欧神話に登場する神々や英雄のモチーフが用いられている点も愛好家に親しまれている。","tags":["highland-park","islands","orkney"]},{"id":"glenmorangie","name":"グレンモーレンジィ","en":"Glenmorangie","lat":57.81,"lon":-4.02,"region":"scotland-highland","founded":1843,"history":"1843年創業、ハイランド北部、ドーノック湾を望むテイン近郊に位置する。スコットランドで最も背の高い蒸留器を持つことで知られ、蒸気が長い首を上る間に重い成分がそぎ落とされ、繊細でフローラルな軽やかな原酒が生まれる。近年はマデイラ樽やポート樽などさまざまな樽での後熟(フィニッシュ)にも積極的に取り組んでいる。","bottles":["グレンモーレンジィ オリジナル","グレンモーレンジィ ラサンタ","グレンモーレンジィ キンタルーバン","グレンモーレンジィ ネクタードール"],"trivia":"蒸留器の高さは約5.14メートルとスコットランドで最も高く、キリンの首ほどの高さがあるとも形容される。その分軽やかで純粋な原酒が生まれると言われ、他の蒸留所も追随してきた。","tags":["glenmorangie","highland","tall-stills"]},{"id":"oban","name":"オーバン","en":"Oban","lat":56.41,"lon":-5.47,"region":"scotland-highland","founded":1794,"history":"1794年、西海岸の港町オーバンの中心部に、スティーヴンソン兄弟によって創業した。町の発展よりも先に蒸留所が築かれ、後から町がその周囲に広がっていったという珍しい成り立ちを持つ。市街地に囲まれ敷地が狭く生産量はごく少ないが、その分ハイランドの穏やかさと沿岸部らしい海の香りが調和した味わいで、根強い人気を誇っている。","bottles":["オーバン14年","オーバン リトルベイ","オーバン ディスティラーズエディション","オーバン18年"],"trivia":"蒸留所の背後には切り立った崖がそそり立ち拡張が難しいため、創業当初から生産規模を大きく変えられないまま長年操業を続ける希少な蒸留所となっている。観光客も多く訪れる。","tags":["oban","highland","coastal"]}]},{"id":"ireland","name":"アイルランド","tagline":"修道院の生命の水から世界三大ウイスキーへ、緑の島の不屈の物語","background":"緑の丘陵と湿った風が吹くアイルランドでは、遠い昔に大陸の修道院から渡った蒸留技術が根付いたと伝わる。修道士たちは薬効を求めて蒸留を重ね、生まれた酒を「ウシュクベーハー」、すなわち生命の水と呼んだ。この言葉こそが、のちに世界共通語となる「ウイスキー」の語源である。\n\n18世紀から19世紀にかけて、ダブリンはウイスキー産業の中心地として栄えた。ジェムソン、パワーズ、ロウ、ウィリアム・ジェムソンという「ビッグフォー」が軒を連ね、麦芽税を避けるため未麦芽の大麦を混ぜたポットスチルウイスキーを確立した。連続式蒸留機コフィースチルが自国の発明家によって生み出されても、蒸留所の多くは伝統の重厚な風味を選び、これを退けた。\n\nだが黄金期は長くは続かなかった。20世紀に入ると独立戦争と英国との貿易摩擦で大英帝国市場を失い、追い打ちをかけるように米国の禁酒法が最大の輸出先を閉ざした。世界に数百とあった蒸留所は次々と姿を消し、アイリッシュウイスキーは存亡の危機に立たされた。\n\n生き残りをかけ、1966年に主要3社はアイリッシュ・ディスティラーズとして統合し、1975年には新ミドルトン蒸留所に生産を集約した。1987年、実業家ジョン・ティーリングが独立系のクーリー蒸留所を設立すると、一世紀ぶりに大手以外からもアイリッシュウイスキーが生まれる道が開かれた。\n\n2010年代に入るとクラフト蒸留所の設立が相次ぎ、ティーリングやウォーターフォードなど新しい造り手が伝統とテロワールへのこだわりを両立させている。修道院の一杯から世界的ブームへ、アイルランドの物語は今も静かに蒸留され続けている。","timeline":[{"year":1170,"era":"origins","icon":"scroll","title":"修道院文化と蒸留技術伝来","text":"大陸の修道院から渡った蒸留技術がアイルランドに根付き、修道士たちが薬用にウシュクベーハー（生命の水）を造り始めたと伝わる。"},{"year":1405,"era":"origins","icon":"scroll","title":"最古の文献記録","text":"クロンマクノイズ年代記に、族長がクリスマスに「アクア・ヴィテ」を飲み過ぎて命を落としたとの記述が残り、現存最古のウイスキー言及とされる。"},{"year":1608,"era":"origins","icon":"law","title":"ブッシュミルズに蒸留免許","text":"国王ジェームズ1世がアントリム県の土地とともに正式な蒸留免許を与え、後のブッシュミルズ蒸留所につながる公式な文書記録が残された。"},{"year":1780,"era":"smuggling","icon":"factory","title":"ジェムソン、ボウ・ストリートで創業","text":"スコットランド出身のジョン・ジェムソンがダブリンのボウ・ストリートに蒸留所を構え、のちの代表銘柄ジェムソンの歴史が始まった。"},{"year":1791,"era":"smuggling","icon":"factory","title":"パワーズ、ジョンズ・レーンで創業","text":"ジェームズ・パワーがダブリンのジョンズ・レーンに蒸留所を開き、ジェムソンと並びダブリン黄金期を支える二大勢力の一角となった。"},{"year":1823,"era":"industrial","icon":"law","title":"消費税法で公認蒸留へ転換","text":"英国議会が消費税法を改正して合法蒸留の免許条件を緩和し、アイルランドでも密造酒づくりから公認蒸留所への転換が急速に進んだ。"},{"year":1830,"era":"industrial","icon":"still","title":"コフィースチルの発明と拒絶","text":"アイルランド人イーニアス・コフィーが連続式蒸留機を発明したが、地元蒸留所の多くは伝統のポットスチルの風味を守り、採用を見送った。"},{"year":1878,"era":"industrial","icon":"trophy","title":"ダブリン・ポットスチルの黄金期","text":"ジェムソン、パワーズ、ロウ、ウィリアム・ジェムソンの「ビッグフォー」が並び立ち、アイリッシュウイスキーは世界最大級の生産量を誇った。"},{"year":1920,"era":"crisis","icon":"fire","title":"独立戦争と禁酒法による市場喪失","text":"独立戦争と英国との貿易摩擦で大英帝国市場を失い、同時期に始まった米国禁酒法が最大の輸出先を閉ざし、業界は急速に縮小した。"},{"year":1966,"era":"crisis","icon":"factory","title":"アイリッシュ・ディスティラーズ設立","text":"生き残りをかけ、ジェムソン、パワーズ、コーク・ディスティラリーズの3社が統合し、アイリッシュ・ディスティラーズ社として生産を一本化した。"},{"year":1975,"era":"crisis","icon":"factory","title":"新ミドルトン蒸留所が稼働","text":"旧ミドルトン蒸留所に代わり最新設備を備えた新ミドルトン蒸留所が稼働を開始し、ジェムソンなど主要銘柄を支える中心的な生産拠点となった。"},{"year":1987,"era":"renaissance","icon":"still","title":"クーリー蒸留所、独立系の先駆け","text":"実業家ジョン・ティーリングが一世紀ぶりの独立系蒸留所クーリーを設立し、大手グループ以外からウイスキーを生む道を切り開いた。"},{"year":2015,"era":"renaissance","icon":"glass","title":"クラフト蒸留所ブームの到来","text":"ティーリングやウォーターフォードなど新世代の蒸留所が相次いで開業し、伝統製法と革新的な熟成実験でアイリッシュウイスキーは復興を遂げた。"}],"distilleries":[{"id":"midleton","name":"ミドルトン","en":"Midleton Distillery","lat":51.92,"lon":-8.17,"region":"ireland","founded":1825,"history":"コーク県ミドルトンで1825年に旧蒸留所として創業し、1966年のアイリッシュ・ディスティラーズ設立を経て、1975年に隣接地へ最新設備の新ミドルトン蒸留所が完成した。ジェムソンをはじめレッドブレストやパワーズなど主要銘柄の大半をここで生産しており、アイリッシュウイスキー最大の生産拠点として業界を支え続けている。旧蒸留所の敷地は見学施設として保存されている。","bottles":["ジェムソン スタンダード","レッドブレスト 12年","ミドルトン ヴェリー・レア","パワーズ ジョンズ・レーン・リリース"],"trivia":"旧ミドルトン蒸留所の敷地には容量約14万3千リットルという、かつて世界最大とされた巨大なポットスチルが今も保存されており、見学者はその圧倒的な大きさに驚かされる。","tags":["midleton","jameson","pot-still"]},{"id":"bushmills","name":"ブッシュミルズ","en":"Old Bushmills Distillery","lat":55.2,"lon":-6.52,"region":"ireland","founded":1608,"history":"北アイルランドのアントリム県、ジャイアンツ・コーズウェイに近いブッシュ川のほとりに位置し、1608年の勅許にちなみ世界最古の免許蒸留所を名乗る。実際の建屋の稼働は18世紀後半にさかのぼるとされるが、以来ほぼ途切れることなく操業を続けてきた。地元産の水と大麦を用いた三回蒸留のシングルモルトを主体とし、ブレンデッドのブラックブッシュでも広く知られる。","bottles":["ブッシュミルズ オリジナル","ブッシュミルズ ブラックブッシュ","ブッシュミルズ 10年","ブッシュミルズ 16年 トリプルウッド"],"trivia":"蒸留に使う仕込み水はブッシュ川の支流セント・コロンズ・リルという小さな川から取水している。一方でブッシュミルズという地名は、ブッシュ川とその流域に点在した水車小屋（ミル）に由来するとされる。","tags":["bushmills","single-malt","northern-ireland"]},{"id":"cooley","name":"クーリー","en":"Cooley Distillery","lat":53.97,"lon":-6.39,"region":"ireland","founded":1987,"history":"ダンドーク近郊クーリー半島の旧工業用アルコール工場を転用し、1987年に実業家ジョン・ティーリングが設立した。大手グループの寡占が続いていた時代に一世紀ぶりの独立系蒸留所として登場し、シングルモルトとグレーンの両方を手がける柔軟な生産体制を築いた。2011年にビーム社（現ビームサントリー）の傘下に入った後も、独自ブランドの生産拠点であり続けている。","bottles":["キルベガン","コネマラ","タイコネル","グリノア"],"trivia":"看板銘柄のひとつコネマラは、無泥炭の伝統が根強いアイルランドでは珍しくピート香をしっかり効かせたシングルモルトとして知られ、愛好家の間で長く異彩を放つ存在になっている。","tags":["cooley","peated","independent"]},{"id":"teeling","name":"ティーリング","en":"Teeling Whiskey Distillery","lat":53.34,"lon":-6.29,"region":"ireland","founded":2015,"history":"クーリー創業者ジョン・ティーリングの息子であるジャックとスティーブンが2015年、ダブリンの歴史的地区リバティーズに設立した。実に125年以上ぶりにダブリン市内で稼働した蒸留所として注目を集め、市中心部でのウイスキー造りを復活させた立役者と評される。多彩な樽仕上げによる実験的なリリースで若い世代の支持を集めている。","bottles":["ティーリング スモールバッチ","ティーリング シングルグレーン","ティーリング シングルモルト","ティーリング シングルポットスチル"],"trivia":"看板銘柄のスモールバッチはカリブ海産のラム樽で追加熟成させており、色鮮やかなラベルデザインとともに、若い世代を惹きつけるダブリン復興の象徴として親しまれている。","tags":["teeling","dublin","craft"]},{"id":"tullamore","name":"タラモアデュー","en":"Tullamore D.E.W. Distillery","lat":53.27,"lon":-7.49,"region":"ireland","founded":1829,"history":"オファリー県タラモアで1829年に創業したが、20世紀半ばの業界縮小のあおりを受け1954年に一度操業を停止した。ブランドは他社の手で存続を保ち続け、2014年にウィリアム・グラント・アンド・サンズ社が地元タラモアに新蒸留所を建設し、ようやく生産が故郷へ戻った。軽やかで飲みやすいブレンデッドウイスキーの代表格として世界中で親しまれている。","bottles":["タラモアデュー オリジナル","タラモアデュー 12年","タラモアデュー フェニックス","タラモアデュー サイダーカスク・フィニッシュ"],"trivia":"「D.E.W.」は20世紀初頭に経営難を救った支配人ダニエル・エドモンド・ウィリアムズの頭文字であり、同時に「朝露」を意味する英単語dewとも掛けた洒落た言葉遊びになっている。","tags":["tullamore","blended","offaly"]},{"id":"waterford","name":"ウォーターフォード","en":"Waterford Distillery","lat":52.26,"lon":-7.11,"region":"ireland","founded":2015,"history":"スコットランドのブルイックラディ再興で知られるマーク・レイニアが2015年、ウォーターフォード市内の旧ギネス系醸造所を転用して設立した。原料大麦を農場単位で管理し、土壌や品種の違いがウイスキーの風味にどう表れるかを追求する「テロワール」志向を前面に打ち出す。各ボトルに畑の情報を記載する取り組みでも注目を集めている。","bottles":["ウォーターフォード シングルファーム・オリジン","ウォーターフォード ザ・キュヴェ","ウォーターフォード アルカディアン・ピーテッド"],"trivia":"販売するボトルのラベルには原料大麦を育てた農場ごとの識別コードが細かく記されており、購入者は専用サイトでその畑の土壌や気候条件まで遡って詳しく確認することができる。","tags":["waterford","terroir","single-farm"]}]},{"id":"england-wales","name":"イングランド＆ウェールズ","tagline":"百年の沈黙を破り、静かに灯った新しい蒸留の火","background":"ブリストルやリバプールといった貿易港を擁するイングランド、そしてウェールズ北部のフロンゴッホ——19世紀のイギリスには、スコットランドの陰に隠れながらも、確かに蒸留の火が灯っていた土地があった。ブリストルの港には穀物を原料とする蒸留所が点在し、リバプールではスコッチのブレンド用原酒として穀物スピリッツが盛んに出荷されていたと伝わる。\n\nなかでもウェールズのフロンゴッホ蒸留所は「ウェルシュ・ウイスキー」の名で一時代を築いた。しかし20世紀の幕開けとともに経営不振に陥り、1900年に売却されたのち1910年に会社が清算されてフロンゴッホは操業を終える。時を同じくしてイングランド側の蒸留所も次々と姿を消し、この二つの土地からウイスキー造りはほぼ丸ごと途絶えてしまった。\n\n長い沈黙が破られたのは2000年のことだった。ウェールズにペンダーリン蒸留所が創業し、マイケル・ファラデーの縁者であるデイヴィッド・ファラデー博士が設計した独自のスチルで、約1世紀ぶりに蒸留の炎を取り戻した。続く2006年にはノーフォークにセント・ジョージズ蒸留所が開業し、イングランドにも本格的なウイスキー造りが帰ってきた。\n\n2014年のコッツウォルズ蒸留所、湖水地方のザ・レイクス、そしてロンドンに次々と誕生した小規模な都市型蒸留所——イングリッシュ・ウイスキーは今や一つの潮流として世界の注目を集めている。生産者たちは自分たちの名称や産地を守るための地理的表示制度についても議論を重ねており、この若きウイスキー産地は今なお自らの物語を書き足している最中である。","timeline":[{"year":1800,"era":"smuggling","icon":"factory","title":"ブリストルの穀物蒸留所","text":"18世紀末から19世紀初頭にかけて、貿易港ブリストルには穀物を原料とする蒸留所が点在し、地元向けにウイスキー様のスピリッツを生産していたと伝わる。"},{"year":1850,"era":"industrial","icon":"ship","title":"リバプールの蒸留業","text":"海運で栄えたリバプールでも穀物蒸留業が盛んになり、スコッチのブレンド用原酒として穀物スピリッツが出荷されていたと伝わる。"},{"year":1887,"era":"industrial","icon":"still","title":"フロンゴッホ蒸留所創業","text":"ウェールズ北部バラ近郊に、地主リチャード・ジョン・ロイド・プライスがフロンゴッホ蒸留所を創業。「ウェルシュ・ウイスキー」の名で売り出した。"},{"year":1910,"era":"crisis","icon":"law","title":"フロンゴッホ終焉、両地域から蒸留が消える","text":"経営不振によりフロンゴッホ蒸留所は1900年に売却され、1910年に会社が清算されて操業を終えた。同時期にイングランド側の蒸留所も姿を消し、両地域からウイスキー造りがほぼ途絶えたと伝わる。"},{"year":2000,"era":"renaissance","icon":"still","title":"ペンダーリン創業、ファラデー式スチル","text":"ウェールズ唯一の蒸留所としてペンダーリンが創業。マイケル・ファラデーの縁者であるデイヴィッド・ファラデー博士が設計した独自のスチル（ファラデー式）を用い、約1世紀ぶりに蒸留の火が灯った。"},{"year":2006,"era":"renaissance","icon":"factory","title":"セント・ジョージズ蒸留所、イングランド復活","text":"ノーフォーク州にセント・ジョージズ蒸留所（ザ・イングリッシュ）が開業。イングランドで約1世紀ぶりの本格的なウイスキー専業蒸留所となった。"},{"year":2014,"era":"renaissance","icon":"trophy","title":"コッツウォルズ蒸留所設立","text":"牧歌的な風景で知られるコッツウォルズ地方に同名の蒸留所が設立され、短期間で国際的な評価を集めイングリッシュ・ウイスキーの新潮流を象徴する存在となった。"},{"year":2015,"era":"renaissance","icon":"glass","title":"ロンドンの都市型蒸留所ブーム","text":"首都ロンドンでもビンバー蒸留所をはじめとする小規模蒸留所が相次いで誕生し、都市型クラフト蒸留のムーブメントが広がった。"},{"year":2018,"era":"renaissance","icon":"law","title":"イングリッシュ・ウイスキーGIを求める議論","text":"生産者団体を中心に「イングリッシュ・ウイスキー」の名称と産地を保護する地理的表示（GI）制度を求める議論が本格化した。"}],"distilleries":[{"id":"penderyn","name":"ペンダーリン","en":"Penderyn","lat":51.8,"lon":-3.56,"region":"england-wales","founded":2000,"history":"ブレコン・ビーコンズ国立公園の麓に位置する、ウェールズ唯一のウイスキー蒸留所として2000年に創業。約1世紀にわたり途絶えていたウェールズの蒸留伝統を復活させた立役者である。マイケル・ファラデーの縁者であるデイヴィッド・ファラデー博士が設計した独自のファラデー式スチルを用い、一度の蒸留で高いアルコール度数の原酒を得る特徴的な製法を採る。2004年に最初のシングルモルトをリリースして以来、ウェールズを代表するブランドへと成長した。","bottles":["ペンダーリン マデイラ","ペンダーリン シェリーウッド","ペンダーリン ポートウッド","ペンダーリン レジェンド"],"trivia":"蒸留所名はウェールズ語で「一番高い場所」を意味する村の名前に由来し、仕込み水には近くのブレコン・ビーコンズの伏流水を使用していると伝わる。","tags":["penderyn","wales","faraday-still","renaissance"]},{"id":"english-whisky-co","name":"ジ・イングリッシュ・ウイスキー・カンパニー","en":"The English Whisky Co.","lat":52.45,"lon":0.9,"region":"england-wales","founded":2006,"history":"ノーフォーク州のセント・ジョージズ蒸留所を拠点に、ネルストロップ親子が2006年に創業。イングランドで約1世紀ぶりに誕生した本格的なウイスキー専業蒸留所として大きな注目を集めた。周囲に広がる自社畑で大麦を栽培するところから瓶詰めまでを一貫して手掛ける姿勢を掲げ、「チャプター」と呼ばれるシリーズで熟成の進み具合を段階的にリリースする手法を特徴とする。","bottles":["イングリッシュ・ウイスキー チャプター6","イングリッシュ・ウイスキー ファウンダーズ・プライベート・セラー","イングリッシュ・ウイスキー ピーテッド"],"trivia":"創業者一家はもともと農業を営んでおり、蒸留所を囲む自社畑で育てた大麦を使う「フィールド・トゥ・ボトル」の姿勢を掲げていると伝わる。","tags":["english-whisky","norfolk","st-georges","renaissance"]},{"id":"cotswolds","name":"コッツウォルズ","en":"Cotswolds Distillery","lat":51.97,"lon":-1.67,"region":"england-wales","founded":2014,"history":"アメリカ出身の元金融マン、ダニエル・ゾール氏が牧歌的な風景で知られるコッツウォルズ地方に2014年に設立。地元産のフロアモルテッド大麦を用い、2017年に最初のシングルモルトをリリースした。近年のイングリッシュ・ウイスキー・ブームを代表する蒸留所の一つとして急速に知名度を高めている。","bottles":["コッツウォルズ シングルモルト","コッツウォルズ ファウンダーズ・チョイス","コッツウォルズ ピーテッド・カスク"],"trivia":"熟成には地元の醸造所やワイナリーと連携した多様なカスクを用いており、自社のジンでも高い評価を得ていると伝わる。","tags":["cotswolds","warwickshire","craft","renaissance"]},{"id":"the-lakes","name":"ザ・レイクス","en":"The Lakes Distillery","lat":54.65,"lon":-3.2,"region":"england-wales","founded":2011,"history":"湖水地方バセンスウェイト湖畔の旧農場跡地に2011年に設立され、2014年から蒸留を開始した。イングランド北部を代表する蒸留所として、美しい自然環境を活かした観光型施設としても知られる。著名なマスターブレンダーが監修に関わったことでも注目を集め、イングランド産ウイスキーの多様性を広げる存在となっている。","bottles":["ザ・ワン","ザ・レイクス ウィスキーメーカーズ・リザーブ","ザ・レイクス ザ・シングルモルト"],"trivia":"蒸留所併設のビジターセンターは湖水地方の観光名所の一つとなっており、羊が草を食む牧草地に囲まれていると伝わる。","tags":["the-lakes","cumbria","lake-district","renaissance"]}]},{"id":"europe","name":"ヨーロッパ大陸・北欧","tagline":"ブランデーとアクアビットの大地に、静かに芽吹いた新参者","background":"ヨーロッパ大陸には、スコットランドのウイスキーよりも古くから根付いた蒸留酒の文化がある。北欧の凍てつく冬を温めてきたアクアビット、コニャック地方でブドウ酒を蒸留して生まれたブランデー、ドイツ語圏で果実を蒸したシュナップス——大陸の人々は麦芽ではなく、手近な穀物や果実で己の酒を育んできた。ウイスキーが大陸に根を下ろすのは、はるか後、20世紀も終わりに近づいてからである。\n\nそれでも大陸とスコッチの縁は深い。とりわけフランスは、量にしてスコッチウイスキー最大級の輸出先に育ち、自国では造らぬ酒を誰よりも愛する消費大国という顔を長く持ち続けてきた。ウイスキーが当たり前に注がれる土地に、いつしか「自分たちの手で造ってみたい」という声が生まれるのは自然な流れだったのかもしれない。\n\nその先陣を切ったのが、ブルターニュ半島のウォーレンゲム蒸溜所である。1900年創業のこの蒸溜所は長らくリキュールなどを手がけていたが、1987年に「WBウイスキー・ブルトン」を送り出し、フランス初の自国産ウイスキーを世に問うた。続くシングルモルト「アルモリック」は、りんご酒の土地で大麦とポットスチルにこだわった一本として、フランスウイスキーの旗手となった。\n\n同じ頃、北の国々でも新しい潮流が生まれていた。1999年創業のスウェーデン・マックミラは、個人が樽やオーナー権を買い支える共同出資的な仕組みで蒸溜所を育て、デンマークのスタウニングは9人の仲間が床式製麦から手がける一本を掲げた。厳しい寒暖差の気候は樽の中身を大きく動かし、独自の熟成の速さをもたらしたといわれる。\n\nドイツやオーストリアでも小さな蒸溜所が各地に生まれ、2010年代にはこうした大陸産シングルモルトが国際的な品評会で評価を得るまでに育った。ブランデーとアクアビットの大地に、ウイスキーという新参者が静かに足場を築きつつある。","timeline":[{"year":1531,"era":"origins","icon":"scroll","title":"アクアビット最古の記録","text":"ベルゲンフス城主のデンマーク貴族エスケ・ビレが、ノルウェー大主教オーラヴ・エンゲルブレクトソンへ薬として「アクアヴィテ」を贈った手紙が残っており、北欧最古のアクアビット関連の記録と伝わる。"},{"year":1600,"era":"origins","icon":"ship","title":"コニャックのブランデー貿易","text":"オランダ商人が輸送効率を求めてブドウ酒を蒸留させたことをきっかけに、コニャック地方でブランデー造りが発展していったと伝わる。"},{"year":1887,"era":"industrial","icon":"law","title":"ドイツの蒸留酒課税制度","text":"ドイツで蒸留酒税法（ブランヴァインシュトイアーゲゼッツ）が制定され、シュナップスなど各地の蒸留酒の生産が国の課税制度のもとに置かれた。この枠組みは後年（1919年）の蒸留酒専売制度の土台になったと伝わる。"},{"year":1970,"era":"crisis","icon":"ship","title":"スコッチ最大級の輸出先","text":"フランスは20世紀後半までにスコッチウイスキー輸出量で世界最大級の市場へと成長し、屈指のウイスキー消費大国として知られるようになった。"},{"year":1983,"era":"renaissance","icon":"factory","title":"ドイツ初のウイスキー蒸溜所","text":"バイエルンでロベルト・フライシュマンがドイツ初のウイスキー蒸溜所ブラウエ・マウスを創業し、大陸に小さな挑戦の火をともした。"},{"year":1987,"era":"renaissance","icon":"factory","title":"フランス初の自国産ウイスキー","text":"ブルターニュのウォーレンゲム蒸溜所が「WBウイスキー・ブルトン」を発表し、フランス初の自国産ウイスキーとして送り出したと伝わる。"},{"year":1998,"era":"renaissance","icon":"still","title":"シングルモルト「アルモリック」誕生","text":"ウォーレンゲムがシングルモルト「アルモリック」を発表し、りんご酒文化の土地ブルターニュにウイスキーの旗を立てたと伝わる。"},{"year":1999,"era":"renaissance","icon":"factory","title":"マックミラ創業","text":"大学時代からの仲間たちがスウェーデンにマックミラを創業。後に樽やオーナー権を個人が買い支える共同出資的な仕組みで成長した。"},{"year":2005,"era":"renaissance","icon":"factory","title":"スタウニング創業","text":"デンマーク西ユラン地方で、医師や料理人ら9人の仲間が古い豚肉加工場を改装してスタウニングを創業し、床式製麦にこだわった。"},{"year":2010,"era":"renaissance","icon":"factory","title":"ハイ・コースト創業","text":"スウェーデンのヘーガ・クステン海岸沿いに、旧木箱工場の建物を利用したボックス蒸溜所（後のハイ・コースト）が新たに創業した。"}],"distilleries":[{"id":"warenghem","name":"ウォーレンゲム","en":"Distillerie Warenghem","lat":48.73,"lon":-3.47,"region":"europe-other","founded":1900,"history":"1900年、レオン・ウォーレンゲムがブルターニュ北岸の町ランニオンに蒸溜所を創業し、当初はリキュールなど各種スピリッツを手がけていた。1987年に「WBウイスキー・ブルトン」でフランス初の自国産ウイスキーを世に送り出し、続いてシングルモルト「アルモリック」を発表。フランスにおけるウイスキー蒸留の先駆者として、今も家族経営を守りながら生産を続けている。","bottles":["アルモリック クラシック","アルモリック ダブルマチュレーション","アルモリック シェリーカスクフィニッシュ","アルモリック ミレジム"],"trivia":"ブルターニュは伝統的にシードルなどりんご酒の文化が根付く土地だが、ウォーレンゲムは大麦とポットスチルにこだわるスコッチ式の造りを貫き、フランスのウイスキー生産を切り拓いた。","tags":["warenghem","armorik","france","brittany"]},{"id":"mackmyra","name":"マックミラ","en":"Mackmyra","lat":60.67,"lon":17.14,"region":"europe-other","founded":1999,"history":"1999年、大学時代からの仲間たちがスウェーデン中部イェヴレ近郊にマックミラを創業し、同国初のウイスキー蒸溜所となった。地元産の大麦とスウェーデンの森林由来の水を用い、冷涼な気候の中でウイスキー造りを行う。2011年には重力を利用して原料を上階から下階へ流す独自構造の新蒸溜所を稼働させ、多くの個人が樽やオーナー権を買い支える仕組みで事業を拡大してきた。","bottles":["マックミラ ブルックスウイスキー","マックミラ スヴェンスク・ルーク","マックミラ スヴェンスク・エーク","マックミラ スペシャル"],"trivia":"森の中に樽を貯蔵する独自の熟成庫を持つほか、原料を建物の最上階に一度だけ運び上げ、あとは重力で下の階へ流しながら仕込みから蒸留まで進める「グラビティ」構造の蒸溜所で知られる。","tags":["mackmyra","sweden","gravity","crowd-investment"]},{"id":"stauning","name":"スタウニング","en":"Stauning Whisky","lat":55.93,"lon":8.28,"region":"europe-other","founded":2005,"history":"2005年、デンマーク西ユラン地方スケアン近郊の小村スタウニングで、医師や料理人、パイロットなど9人の仲間がウイスキー好きの情熱から蒸溜所を立ち上げた。古い豚肉加工場の建物を改装し、地元産の大麦やライ麦を自ら床式製麦するところから手がける。デンマーク王国最古のウイスキー蒸溜所として知られ、後に外部資本も入りながら生産規模を広げていった。","bottles":["スタウニング ライ","スタウニング スモーク","スタウニング カオス","スタウニング バスタード"],"trivia":"床の上に麦を広げて手作業で発芽させる床式製麦を今も自社で行う数少ない蒸溜所であり、ライ麦を使った「スタウニング ライ」は大陸ヨーロッパ産としては珍しいライウイスキーとして評価を集めた。","tags":["stauning","denmark","rye","floor-malting"]},{"id":"high-coast","name":"ハイ・コースト","en":"High Coast Distillery","lat":62.85,"lon":17.83,"region":"europe-other","founded":2010,"history":"2010年、スウェーデン中部のヘーガ・クステン（ハイ・コースト）と呼ばれる世界遺産の海岸沿い、オンゲルマン川のほとりに蒸溜所が創業した。かつて木箱工場だった建物を利用したことから当初は「ボックス蒸溜所」と名乗っていたが、2018年に商標をめぐる事情から「ハイ・コースト」へと改称した。スコットランド式のポットスチルでピーテッド・非ピーテッド双方の原酒を仕込んでいる。","bottles":["ハイ・コースト ハヴ","ハイ・コースト ベリィ","ハイ・コースト ティンメル","ハイ・コースト ドルヴェ"],"trivia":"北緯63度に位置し、夏と冬の寒暖差が非常に大きいこの土地では、樽の中の原酒が季節ごとに大きく伸縮するため、本場スコットランドより速いペースで熟成が進むといわれる。","tags":["high-coast","box","sweden","hoga-kusten"]}]},{"id":"usa","name":"アメリカ","tagline":"開拓の大地で生まれた、もうひとつの琥珀色","background":"アメリカのウイスキーの物語は、大西洋を渡った移民たちの記憶から始まる。植民地時代、東海岸では西インド諸島から運ばれる糖蜜でラム酒がつくられ、これが当初の主役だった。だがイギリスの課税や独立戦争を経て交易網が揺らぐと、人々は手元の穀物に目を向けるようになる。とりわけスコットランドやアイルランドから移り住んだ人々は、故郷仕込みの蒸留技術を携えていた。\n\n18世紀末、彼らの多くは東部の税から逃れるようにアパラチア山脈を越え、ケンタッキーの地に落ち着く。そこは石灰岩層に濾過された清らかな水と、トウモロコシがよく育つ肥沃な土壌に恵まれていた。ライ麦から始まった蒸留は、やがてこの土地の主作物であるトウモロコシを主原料とする独自の酒へと姿を変えていく。焦がした樽で熟成させる製法が広まり、琥珀色と香ばしい風味を持つバーボンが形づくられた。\n\nしかし道のりは平坦ではなかった。新生国家の財政を支えるための酒税は開拓農民の反発を招き、武装蜂起にまで発展する。19世紀を通じて品質を巡る混乱や粗悪品の横行が続いたが、瓶詰め販売の導入や連邦法による規格の整備が、業界に信頼を取り戻していった。\n\n最大の試練は20世紀初頭の禁酒法だった。多くの蒸留所が姿を消し、わずかに認められた医療用ウイスキーの免許だけが灯を絶やさなかった。廃止後の復興と戦後の黄金期を経て、1964年には連邦議会がバーボンを「アメリカ固有の産品」と宣言するに至る。\n\n20世紀後半の低迷期には、大量生産される安価なウイスキーへの飽きから消費が落ち込んだが、シングルバレルやスモールバッチといった高付加価値な製品が新たな道を切り開いた。そして21世紀、全米各地に小規模なクラフト蒸留所が次々と誕生し、アメリカンウイスキーはかつてない多様性と活気を取り戻している。","timeline":[{"year":1620,"era":"origins","icon":"ship","title":"植民地とラム・ライの時代","text":"東海岸の入植地では西インド諸島から運ばれる糖蜜でラム酒がつくられ、開拓者たちの暮らしに蒸留酒の文化が根付き始めたと伝わる。"},{"year":1720,"era":"smuggling","icon":"scroll","title":"スコッチアイリッシュの入植","text":"スコットランドやアイルランドからの移民が増え、彼らが故郷から携えてきた蒸留の技術がライ麦ウイスキーづくりとして広まっていった。"},{"year":1789,"era":"smuggling","icon":"barrel","title":"エライジャ・クレイグと焦がし樽の伝承","text":"バプテスト派の牧師エライジャ・クレイグが誤って焦がした樽で熟成させたウイスキーがバーボンの原型のひとつになったと伝わる。"},{"year":1791,"era":"smuggling","icon":"law","title":"ウイスキー税と反乱","text":"新政府が独立戦争の債務を返済するため蒸留酒に連邦税を課し、これに反発したペンシルベニアの農民たちが武装蜂起を起こす事態に発展した。"},{"year":1794,"era":"smuggling","icon":"still","title":"ケンタッキー開拓とコーンウイスキー","text":"課税を逃れた開拓者たちがアパラチア山脈を越えてケンタッキーへ移住し、豊富に育つトウモロコシを主原料とする独自の蒸留が広まっていった。"},{"year":1825,"era":"industrial","icon":"factory","title":"リンカーン・カウンティ・プロセスの定着","text":"サトウカエデの木炭でウイスキーを濾過する製法がテネシー一帯で定着し、後にリンカーン・カウンティ・プロセスと呼ばれるようになった。"},{"year":1870,"era":"industrial","icon":"barrel","title":"オールド・フォレスターの瓶詰め販売","text":"ジョージ・ガーヴィン・ブラウンが粗悪な樽出しウイスキーへの対策として、封をした瓶で品質を保証しながら販売する方式を始めた。"},{"year":1897,"era":"industrial","icon":"law","title":"ボトルド・イン・ボンド法の制定","text":"連邦政府が熟成年数や度数、蒸留場所を保証する規格を法制化し、粗悪品が横行していた業界に消費者の信頼を取り戻す転機となった。"},{"year":1920,"era":"crisis","icon":"law","title":"禁酒法とメディシナルウイスキー","text":"合衆国憲法修正第18条により酒類の製造・販売が禁じられ、多くの蒸留所が閉鎖される中、医師の処方箋による医療用ウイスキーだけが認められた。"},{"year":1933,"era":"crisis","icon":"trophy","title":"禁酒法の廃止","text":"修正第21条により13年に及んだ禁酒法がついに撤廃され、生き残った蒸留所を中心に生産設備の再建と業界全体の立て直しが始まった。"},{"year":1950,"era":"crisis","icon":"factory","title":"戦後のバーボン黄金期","text":"戦後の好景気とともにバーボンの生産と消費が大きく拡大し、家庭の食卓や社交の場に広く定着してアメリカを代表する酒として花開いた。"},{"year":1964,"era":"crisis","icon":"crown","title":"「アメリカ固有の産品」決議","text":"連邦議会がバーボンウイスキーをアメリカ固有の産品と正式に宣言し、他国産の蒸留酒との差別化を法的に裏付ける重要な根拠となった。"},{"year":1980,"era":"crisis","icon":"glass","title":"バーボン不況の時代","text":"軽い口当たりのウォッカや洋酒に消費者の嗜好が移り、バーボンの販売は長期にわたり低迷して閉鎖に追い込まれる蒸留所も相次いだ。"},{"year":1984,"era":"renaissance","icon":"trophy","title":"シングルバレルの登場","text":"ブラントンズが単一の樽から瓶詰めするシングルバレル・バーボンを発売し、高付加価値なプレミアム路線を切り開く先駆けとなった。"},{"year":2005,"era":"renaissance","icon":"globe","title":"クラフト蒸留所ブームの到来","text":"小規模免許の緩和や消費者の関心の高まりを受け、全米各地に個性豊かなクラフト蒸留所が相次いで誕生し新たな活気をもたらした。"}],"distilleries":[{"id":"jim-beam","name":"ジムビーム","en":"Jim Beam","lat":37.83,"lon":-85.2,"region":"usa-kentucky","founded":1795,"history":"ドイツ系移民ヨハネス・ジェイコブ・ビームに始まる一族が、200年以上にわたり蒸留の家業を営み続けてきた。ケンタッキー開拓の時代から穀物栽培とともに蒸留を手がけ、禁酒法明けにはジェイムズ・B・ビームが荒れ果てた蒸留所を再建し、自らの名を冠したブランドとして再出発させた。現在も一族の血を引く蒸留責任者が伝統を受け継ぎ、世界で最も売れるバーボンのひとつとして親しまれている。","bottles":["ジムビーム ホワイト","ジムビーム ブラック","ジムビーム ダブルオーク","ノブクリーク","ベイカーズ"],"trivia":"ビーム家は初代ヨハネスから数えて7世代にわたり蒸留の家業を続けており、アメリカで最も長く事業を続けているウイスキー一族のひとつと広く言われている、由緒ある家系である。","tags":["jim-beam","family-owned","kentucky"]},{"id":"makers-mark","name":"メーカーズマーク","en":"Maker's Mark","lat":37.69,"lon":-85.41,"region":"usa-kentucky","founded":1953,"history":"ビル・サミュエルズ・シニアが、それまで主流だった刺激の強いライ麦主体のバーボンとは異なる、小麦を使った柔らかい味わいを目指して家族総出で創業した。パンを焼いて小麦の配合を試したという逸話も残る。妻マージのアイデアとされる手作業の赤い封蝋が瓶の目印となり、今ではブランド全体を象徴するデザインとして世界的に知られるようになった。","bottles":["メーカーズマーク","メーカーズマーク46","メーカーズマーク カスクストレングス"],"trivia":"瓶の口を赤い蝋で封じる作業は今も機械化せず、一本ずつ職人の手作業でディップして仕上げられていると伝わる、ブランドを象徴する大切な工程として世界中で知られている。","tags":["makers-mark","wheated-bourbon","kentucky"]},{"id":"wild-turkey","name":"ワイルドターキー","en":"Wild Turkey","lat":38.05,"lon":-84.73,"region":"usa-kentucky","founded":1869,"history":"七面鳥狩りの遠征に持参されたウイスキーが仲間内で好評だったことから名付けられたと伝わる。もとは他社向けの原酒供給が中心だったが、伝説的なマスターディスティラー、ジミー・ラッセルが半世紀以上にわたり品質を守り続け、高いアルコール度数と力強い味わいで根強いファンを持つブランドへと育て上げた、南部らしい骨太な個性を持つ蒸留所である。","bottles":["ワイルドターキー 8年","ワイルドターキー101","ラッセルズ・リザーブ","ロングブランチ"],"trivia":"ジミー・ラッセルは息子エディとともに親子二代でマスターディスティラーを務めた時期があり、業界でも珍しい親子共同の体制として長く多くのファンから親しまれ続けてきた。","tags":["wild-turkey","high-proof","kentucky"]},{"id":"four-roses","name":"フォアローゼス","en":"Four Roses","lat":37.83,"lon":-84.87,"region":"usa-kentucky","founded":1888,"history":"創業者ポール・ジョーンズ・ジュニアが求婚の返事として赤いバラのコサージュを贈られた逸話にちなむと伝わる。長らく国内では低価格帯のブレンド原酒供給元という控えめな位置づけだったが、日本市場での高い評価をきっかけに本国でも見直され、今では奥深い個性を持つプレミアムブランドとして高く再評価されるに至っている。","bottles":["フォアローゼス イエローラベル","フォアローゼス ブラック","フォアローゼス スモールバッチ","シングルバレル"],"trivia":"2種類のマッシュビルと5種類の酵母を組み合わせた10種類のレシピを使い分けており、これが複雑で奥行きのある香りの構成を生み出す秘訣になっていると広く伝わっている。","tags":["four-roses","recipe-blending","kentucky"]},{"id":"buffalo-trace","name":"バッファロートレース","en":"Buffalo Trace","lat":38.2,"lon":-84.87,"region":"usa-kentucky","founded":1773,"history":"バッファローの群れが渡った古い道の跡地に建てられたことが名の由来と伝わる、アメリカ最古級の稼働蒸留所のひとつ。禁酒法の間も医療用ウイスキーの免許で操業を続けた数少ない蒸留所であり、幾度も社名を変えながら生き延びてきた。現在は伝統的な銘柄から実験的な少量リリースまで幅広く手がける先進的な蒸留所として知られている。","bottles":["バッファロートレース","エンシェントエイジ","イーグルレア","ブラントン"],"trivia":"禁酒法下でも稼働を許された数少ない蒸留所のひとつで、その稼働の連続性がアメリカ国定歴史建造物としての指定にもつながったと伝わっている、由緒ある特別な場所である。","tags":["buffalo-trace","national-historic-landmark","kentucky"]},{"id":"woodford-reserve","name":"ウッドフォードリザーブ","en":"Woodford Reserve","lat":38.07,"lon":-84.68,"region":"usa-kentucky","founded":1812,"history":"ケンタッキー州最古級の蒸留所のひとつとされる敷地に建ち、スコットランド式の銅製ポットスチルを用いた三回蒸留を特徴とする。一時は操業を停止していたが1990年代に大手企業の手で復活し、丘陵に囲まれた美しい景観と丁寧な蒸留工程から、ケンタッキーダービーの公式バーボンとしても長く採用され続けている名門である。","bottles":["ウッドフォードリザーブ ディスティラーズセレクト","ダブルオークド","バーボンバレル ライ"],"trivia":"蒸留所の敷地全体がアメリカ国定歴史建造物に登録されており、優雅な建物群と豊かな自然に囲まれた観光地として、年間を通じて世界中から実に多くの見学者を絶えず集め続けている。","tags":["woodford-reserve","pot-still","kentucky"]},{"id":"jack-daniels","name":"ジャックダニエル","en":"Jack Daniel's","lat":35.28,"lon":-86.39,"region":"usa-tennessee","founded":1866,"history":"少年の頃から蒸留を学んだジャスパー・ニュートン・「ジャック」・ダニエルが、テネシー州リンチバーグに設立した。サトウカエデの木炭でウイスキーをゆっくりと濾過するチャコール・メローイング製法を用い、バーボンとは一線を画すテネシーウイスキーとして世界的な知名度を確立した。四角い瓶と黒いラベルのデザインも早くから統一され、ブランドの象徴となっている。","bottles":["ジャックダニエル オールド No.7","ジェントルマンジャック","シングルバレル セレクト","テネシーハニー"],"trivia":"本拠地のムーア郡は今も禁酒法（ドライ郡）を採用しており、蒸留所を訪れても一般客への通常販売ができないという珍しい逸話が今も語り継がれている、興味深い土地柄である。","tags":["jack-daniels","tennessee-whiskey","charcoal-mellowing"]},{"id":"george-dickel","name":"ジョージディッケル","en":"George Dickel","lat":35.42,"lon":-86.09,"region":"usa-tennessee","founded":1870,"history":"ドイツ系移民の酒商ジョージ・ディッケルの名を冠した、まろやかな飲み口を身上とする蒸留所。カスケードホロウの地に築かれた蒸留所は、原酒を冬場のように冷やしてから木炭でゆっくりと濾過する独自の工程を採用し、スコットランド式の伝統に敬意を表して綴りにもこだわったと伝わる。禁酒法期には一時操業を停止したが、後に再建されテネシーを代表する蒸留所のひとつとなった。","bottles":["ジョージディッケル No.8","ジョージディッケル No.12","バレルセレクト","ライウイスキー"],"trivia":"多くのアメリカンウイスキーが whiskey と綴る中、同社はスコットランド式に敬意を表して whisky と表記していることで広く知られている珍しい存在である。","tags":["george-dickel","tennessee-whiskey","chill-charcoal-filtering"]}]},{"id":"canada","name":"カナダ","tagline":"製粉業者の副業から生まれた、ライの国のウイスキー","background":"カナダのウイスキーは、五大湖沿岸やセントローレンス川流域に入植した製粉業者たちの副業から始まった。小麦を挽いた後に残るライ麦の余剰を無駄にしないため、18世紀後半、農民や粉屋たちは簡易な蒸留器で穀物を蒸留し始めた。ライ麦特有のスパイシーな香りは酒の個性となり、やがて「カナディアンウイスキー」といえば「ライウイスキー」を指すほど、両者は分かちがたく結びついた。\n\n19世紀に入ると、製粉業は本格的な蒸留産業へと姿を変える。トロントのグーダーハム&ワーツは製粉所に蒸留設備を加えて世界最大級の蒸留所に成長し、アメリカから渡ったハイラム・ウォーカーはオンタリオ州ウィンザーの対岸に企業城下町ウォーカーヴィルを築いた。鉄道網の拡大とともに、カナディアンウイスキーは輸出用の産業製品となっていった。\n\n転機はアメリカの禁酒法だった。1920年から1933年まで、対岸のデトロイトへ酒を密輸する船が毎夜デトロイト川を渡り、ウィンザーは密造酒交易の一大拠点となった。この混乱期を乗りこなしたのが、サム・ブロンフマンとその一族である。蒸留会社を次々と買収し、シーグラムは瞬く間に世界最大級の酒類企業へ成長した。\n\n1939年、英国王ジョージ6世夫妻のカナダ訪問を記念してクラウンローヤルが誕生し、王室にふさわしい滑らかな味わいが評判を呼んだ。戦後は軽やかな酒質のカナディアンウイスキーがアメリカ市場を席巻し、輸入ウイスキーの代名詞となる。しかし絶頂を極めたシーグラム帝国も、2000年前後には解体され、資産は世界の酒類大手へ分割された。\n\n近年は、他の酒類を全体の9.09%まで加えて風味付けできる独自の規則を活かしながら、グレンオラのようなシングルモルトの挑戦者や、フォーティ・クリークのように緻密なブレンドで個性を追求する小規模蒸留所が台頭している。素朴な副業から始まった物語は、今も新しい章を書き加え続けている。","timeline":[{"year":1769,"era":"origins","icon":"still","title":"製粉業者のかたわら仕事","text":"オンタリオやケベックの製粉業者たちが、小麦を挽いた後に残るライ麦の余剰を無駄にせず、簡易な蒸留器で穀物スピリッツを造り始めたと伝わる。これがカナダにおけるウイスキー造りの起点とされる。"},{"year":1801,"era":"origins","icon":"factory","title":"モルソン、蒸留を開始","text":"モントリオールでビール醸造業を営んでいたジョン・モルソンが、穀物蒸留にも事業を広げた。カナダで最も早い時期に確認できる商業蒸留の記録のひとつとされる。"},{"year":1837,"era":"industrial","icon":"factory","title":"グーダーハム&ワーツ創業","text":"トロントの風車製粉所ワーツ&グーダーハムが蒸留設備を導入し、余剰穀物からウイスキー造りを始めた。後に一時、世界最大級の蒸留所へと成長していく。"},{"year":1858,"era":"industrial","icon":"factory","title":"ハイラム・ウォーカー、ウィンザーへ","text":"アメリカ人実業家ハイラム・ウォーカーがデトロイト川対岸のオンタリオ州に渡り蒸留所を設立、企業城下町ウォーカーヴィルを築いた。後のカナディアンクラブの母体である。"},{"year":1883,"era":"industrial","icon":"barrel","title":"シーグラムの原点","text":"ジョセフ・E・シーグラムがウォータールーの蒸留所の経営権を握り、自らの名を冠したブランドを育て始めた。後の巨大企業シーグラムの原点となる出来事である。"},{"year":1920,"era":"smuggling","icon":"ship","title":"禁酒法と密輸の黄金期","text":"アメリカで禁酒法が施行されると、ウィンザーとデトロイトを隔てる川は密輸船が行き交う舞台となった。合法的に造られたカナディアンウイスキーは、隣国への裏の輸出で潤った。"},{"year":1928,"era":"crisis","icon":"trophy","title":"ブロンフマン、シーグラムを掌握","text":"サム・ブロンフマン率いる一族が蒸留会社を次々と統合し、シーグラムを世界最大級の酒類企業へと押し上げた。カナディアンウイスキーは国際的な存在感を強めていく。"},{"year":1939,"era":"crisis","icon":"crown","title":"クラウンローヤル誕生","text":"英国王ジョージ6世夫妻のカナダ訪問を記念し、シーグラム社が特別なブレンドを献上、後にクラウンローヤルとして発売された。王冠を模したボトルが今も特徴である。"},{"year":1953,"era":"crisis","icon":"glass","title":"軽やかな酒質が北米を席巻","text":"戦後のアメリカ市場では、まろやかで軽やかな口当たりのカナディアンウイスキーが人気を集め、長らく輸入ウイスキーの販売量首位を占める存在となった。"},{"year":1990,"era":"renaissance","icon":"law","title":"グレンオラ、北米初のシングルモルトへ","text":"ノバスコシア州グレンヴィルにグレンオラ蒸留所が誕生し、北米初のシングルモルトウイスキーに挑んだ。「グレン」の名称をめぐりスコッチウイスキー協会と長い係争を経験した。"},{"year":2000,"era":"renaissance","icon":"fire","title":"シーグラム帝国の解体","text":"世界最大級を誇ったシーグラムの酒類事業は、2000年前後に売却・分割され、傘下ブランドは複数の国際企業へと引き継がれていった。"},{"year":2019,"era":"renaissance","icon":"law","title":"9.09%ルールとクラフトの台頭","text":"他の酒類を全体の9.09%まで加えて風味付けできるという独自規則が改めて注目を集める一方、フォーティ・クリークなど小規模蒸留所が個性的なブレンドで存在感を示している。"}],"distilleries":[{"id":"hiram-walker","name":"ハイラム・ウォーカー","en":"Hiram Walker & Sons","lat":42.3,"lon":-83.03,"region":"canada","founded":1858,"history":"1858年、アメリカ人実業家ハイラム・ウォーカーがデトロイト川を渡りオンタリオ州に蒸留所を設立し、従業員のための企業城下町ウォーカーヴィルを築いた。1884年に売り出したカナディアンクラブは瞬く間に北米で人気を博し、禁酒法時代には対岸への密輸品としても重宝された。現在も北米最大級の稼働蒸留所のひとつとして、多彩なブランドを生み出し続けている。","bottles":["カナディアンクラブ12年","カナディアンクラブ20年","ロット No.40","パイククリーク","グーダーハム&ワーツ ライ"],"trivia":"禁酒法時代、密輸業者はウィンザーからデトロイトへ小型ボートやそりで酒を運び、川面が凍る冬には氷上を車で渡る者まで現れたという。当時の密輸量は正規の輸出量を大きく上回っていたと伝わる。","tags":["hiram-walker","canadian-club","windsor","prohibition"]},{"id":"crown-royal","name":"クラウンローヤル","en":"Crown Royal","lat":50.63,"lon":-97.0,"region":"canada","founded":1968,"history":"1939年の英国王ジョージ6世夫妻のカナダ訪問を記念し、シーグラム社が特別なウイスキーを献上したことがブランドの始まりと伝わる。専用の蒸留所は1968年、マニトバ州ギムリの地に建設され、以来この一か所でクラウンローヤルのすべてが仕込まれている。紫の巾着袋に包まれた王冠形のボトルは、今も北米で最も親しまれるカナディアンウイスキーのひとつである。","bottles":["クラウンローヤル デラックス","クラウンローヤル ブラック","クラウンローヤル リザーブ","クラウンローヤル ノーザンハーベストライ","クラウンローヤル XR"],"trivia":"紫色の巾着袋は当初、輸送中のボトルを傷から守るための実用的な工夫だったが、いつしか贈答用の袋としてそのまま珍重されるようになり、今ではブランドを象徴する意匠のひとつになっている。","tags":["crown-royal","gimli","seagram","royal"]},{"id":"alberta-distillers","name":"アルバータ・ディスティラーズ","en":"Alberta Distillers Ltd.","lat":51.05,"lon":-114.07,"region":"canada","founded":1946,"history":"1946年、カルガリーに設立されたアルバータ・ディスティラーズは、周辺の肥沃な農地で育つ良質なライ麦に着目し、100%ライ麦を原料とする高濃度のライウイスキー造りを追求してきた。厳しい寒暖差のあるアルバータの気候は熟成にも独特の個性を与え、他社が手掛けるブレンデッドウイスキー用の原酒としても長く高く評価され続けている。","bottles":["アルバータ プレミアム","アルバータ プレミアム カスクストレングス","アルバータ プレミアム ダークホース","テングルリッジ"],"trivia":"多くのカナディアンウイスキーがトウモロコシを主原料とする中、アルバータ・ディスティラーズは一貫して100%ライ麦にこだわり続けてきた数少ない蒸留所のひとつとして知られている。","tags":["alberta-distillers","calgary","rye","high-rye"]},{"id":"glenora","name":"グレンオラ","en":"Glenora Distillery","lat":46.11,"lon":-61.24,"region":"canada","founded":1990,"history":"1990年、スコットランド系移民の伝統が色濃く残るノバスコシア州ケープブレトン島に、北米初のシングルモルトウイスキー蒸留所としてグレンオラが誕生した。スコッチウイスキー協会からは「グレン」の名称使用を巡り異議を申し立てられ、長い法廷闘争の末にラベル上での使用を認められた経緯を持つ、北米シングルモルトの草分け的存在である。","bottles":["グレン ブレトン レア","グレン ブレトン アイス","グレン ブレトン バトル オブ ザ グレン"],"trivia":"スコッチウイスキー協会との係争では最終的にカナダの裁判所がグレンオラ側を支持し、「グレン」の名称を維持できたことがシングルモルト愛好家の間で語り草になっている。","tags":["glenora","nova-scotia","single-malt","cape-breton"]},{"id":"forty-creek","name":"フォーティ・クリーク","en":"Forty Creek Distillery","lat":43.2,"lon":-79.57,"region":"canada","founded":1992,"history":"元ワインメーカーのジョン・ホールが1992年、オンタリオ州グリムズビーのブドウ園跡地に開いた小規模蒸留所である。トウモロコシ・ライ麦・大麦をそれぞれ別々に蒸留・熟成させたのち、丁寧にブレンドするという独自の手法で、カナディアンウイスキーに新しい表現をもたらし、業界内外から高い評価を得ている、いわばクラフト蒸留所の草分けである。","bottles":["フォーティクリーク バレルセレクト","フォーティクリーク コパーポットリザーブ","フォーティクリーク コンフェデレーションオーク","フォーティクリーク ダブルバレルリザーブ"],"trivia":"ワイン造りの経験を持つ創業者は、原料穀物ごとに別々の樽で仕込み熟成させる独自製法を確立し、カナディアンウイスキー業界に新風を吹き込んだ人物として広く知られている。","tags":["forty-creek","grimsby","blending","craft"]}]},{"id":"japan","name":"日本","tagline":"模造酒から世界基準へ、水と霧が育てた東洋の蒸溜哲学","background":"日本にウイスキーがもたらされたのは幕末の開国期で、横浜や神戸の外国人居留地を通じて珍しい舶来の酒として紹介された。国産化はまず輸入原酒に着色料や香料を加える模造酒から始まり、本物の蒸溜酒を造ろうという志は大正から昭和にかけてようやく形になっていく。\n\nその先駆けとなったのが、大阪の商人鳥井信治郎と、スコットランドで本場の製法を学んだ竹鶴政孝である。二人は水と霧に恵まれた京都・大阪の境、山崎の地に日本初の本格モルトウイスキー蒸溜所を築き、幾度もの試行錯誤を経てようやく日本人の舌に合う一本を完成させた。\n\nやがて袂を分かった竹鶴は、スコットランドの風土に似た北海道の余市に自らの蒸溜所を構え、後にニッカウヰスキーとなる道を歩み始める。戦後の混乱期には安価なウイスキーを気軽に飲めるバー文化が花開き、洋酒は復興期の日本人にとって新しい豊かさの象徴となった。\n\n1983年の消費ピークを境に、日本のウイスキーは長い低迷の時代に入る。それでも各蒸溜所は原酒の質を落とすことなく熟成を続け、2003年の国際的な受賞をきっかけに世界がその実力に気づき始めた。ハイボールブームや朝の連続テレビ小説も追い風となり、国内でも再び人気に火が付いた。\n\n現在では秩父や厚岸、嘉之助といった小規模な新興蒸溜所が各地で個性を競い合い、「ジャパニーズウイスキー」は伝統と革新が同居する世界的なカテゴリーへと成長している。","timeline":[{"year":1871,"era":"industrial","icon":"factory","title":"洋酒模造の時代","text":"開国後、輸入洋酒に安価なアルコールや香料を混ぜた模造ウイスキーが横浜・神戸で盛んに製造され、日本人が初めて洋酒の味を知る入り口となった。"},{"year":1899,"era":"industrial","icon":"glass","title":"鳥井信治郎、寿屋を創業","text":"大阪で薬種問屋から身を起こした鳥井信治郎が寿屋(後のサントリー)を創業し、赤玉ポートワインなどの洋酒事業で本格ウイスキー製造への布石を築いた。"},{"year":1918,"era":"crisis","icon":"scroll","title":"竹鶴政孝、スコットランド留学と竹鶴ノート","text":"竹鶴政孝がグラスゴー大学に留学し、複数の蒸溜所で実地研修を積んだ末に製法を克明に記した「竹鶴ノート」を持ち帰り、日本のウイスキー造りの礎を築いた。"},{"year":1923,"era":"crisis","icon":"still","title":"山崎蒸溜所着工","text":"鳥井信治郎が竹鶴を技師長に迎え、水質と気候に恵まれた京都・大阪境の山崎に日本初の本格モルトウイスキー蒸溜所の建設に着手した。"},{"year":1929,"era":"crisis","icon":"barrel","title":"白札、発売","text":"サントリー初の本格ウイスキー「白札(サントリーウイスキー)」が発売されたが、スコッチに寄せた煙たい香りは当時の日本人の口に合わず苦戦した。"},{"year":1934,"era":"crisis","icon":"factory","title":"大日本果汁設立と余市蒸溜所","text":"寿屋を退社した竹鶴政孝が、スコットランドに気候の似た北海道余市に大日本果汁(後のニッカウヰスキー)を設立し、独立して蒸溜所を築いた。"},{"year":1950,"era":"crisis","icon":"glass","title":"戦後のウイスキーブームとトリス・バー","text":"戦後復興期、安価なトリスウイスキーを気軽に飲める「トリス・バー」が全国に広がり、洋酒は庶民の新しい娯楽文化として定着していった。"},{"year":1953,"era":"crisis","icon":"law","title":"級別制度の確立","text":"酒税法に基づき特級・1級・2級に分類する級別制度が整備され、税額や品質イメージが等級で規定される時代が長く続くことになった。"},{"year":1969,"era":"crisis","icon":"still","title":"宮城峡蒸溜所、誕生","text":"竹鶴政孝が余市に続く第二の拠点として仙台近郊の渓谷を選び、余市とは対照的な穏やかでフルーティーな原酒を生む宮城峡蒸溜所を稼働させた。"},{"year":1980,"era":"renaissance","icon":"factory","title":"地ウイスキーブーム","text":"全国各地の酒造メーカーが相次いでウイスキー製造に参入し、地域色を打ち出した「地ウイスキー」が数多く登場して市場を賑わせた。"},{"year":1983,"era":"renaissance","icon":"fire","title":"国内消費ピークと長期低迷の始まり","text":"国内のウイスキー消費量が過去最高を記録した1983年をピークに、その後は焼酎や酎ハイの台頭もあり二十年以上続く長い低迷期に入った。"},{"year":2003,"era":"renaissance","icon":"trophy","title":"山崎12年、ISCで金賞","text":"「山崎12年」が国際的な品評会インターナショナル・スピリッツ・チャレンジで金賞を受賞し、ジャパニーズウイスキーが世界的評価を得る転機となった。"},{"year":2008,"era":"renaissance","icon":"glass","title":"ハイボールブーム","text":"サントリーの「角ハイボール」キャンペーンをきっかけに炭酸割りのウイスキーが若年層にも広がり、国内消費が久々に上向くきっかけとなった。"},{"year":2014,"era":"renaissance","icon":"crown","title":"竹鶴夫妻、NHK朝ドラで脚光","text":"竹鶴政孝とリタ夫妻をモデルにしたNHK連続テレビ小説「マッサン」が放送され、ジャパニーズウイスキーの歴史が広く一般に知られるきっかけとなった。"},{"year":2021,"era":"renaissance","icon":"law","title":"ジャパニーズウイスキー表示基準の策定","text":"日本洋酒酒造組合が国産原料・国内蒸溜・国内熟成などを条件とする「ジャパニーズウイスキー」の自主基準を定め、表示の適正化に踏み出した。"}],"distilleries":[{"id":"yamazaki","name":"山崎","en":"The Yamazaki","lat":34.88,"lon":135.67,"region":"japan","founded":1923,"history":"鳥井信治郎が竹鶴政孝を技師長に迎え、木津川・宇治川・桂川が合流する京都・大阪境の山崎に、日本で初めての本格モルトウイスキー蒸溜所を建設した。良質な伏流水と一年を通じて立ちこめる深い霧が熟成に適するとされ、単式蒸溜器の形状や樽の種類をあえて多様化させることで、一つの蒸溜所から驚くほど幅広い個性の原酒を生み出す独自の哲学が育まれた。以来サントリーの看板蒸溜所として、原酒造りの中心を担い続けている。","bottles":["山崎12年","山崎18年","山崎25年","山崎ノンエイジ"],"trivia":"2003年、山崎12年が国際的な品評会ISC(インターナショナル・スピリッツ・チャレンジ)で金賞を受賞し、これが世界的な「ジャパニーズウイスキー」評価の出発点になったと言われる。","tags":["yamazaki","suntory","sherry-cask","mizunara"]},{"id":"hakushu","name":"白州","en":"The Hakushu","lat":35.79,"lon":138.43,"region":"japan","founded":1973,"history":"南アルプスの麓、標高700メートルの白州の森に建てられたサントリー第二のモルト蒸溜所。深い森と尾白川の伏流水に囲まれた「森の蒸溜所」として知られ、軽やかでありながらほのかにスモーキーなニュアンスも併せ持つ原酒を生む。バーボン樽やミズナラ樽など多彩な貯蔵で個性を育てながら、蒸溜所内の広大な森を活かした自然共生型の運営でも知られている。","bottles":["白州12年","白州18年","白州ノンエイジ","白州 蒸溜所限定"],"trivia":"蒸溜所内には野鳥の森が広がり、四季折々の自然観察もできる自然共生型の施設として知られる。仕込み水は南アルプス天然水と同じ水源から採られており、蒸溜所見学者にはこの名水を使ったハイボールが振る舞われる。","tags":["hakushu","suntory","mountain","smoky"]},{"id":"chita","name":"知多","en":"The Chita","lat":34.93,"lon":136.86,"region":"japan","founded":1972,"history":"愛知県知多半島に構えるサントリーのグレーンウイスキー専用蒸溜所。連続式蒸溜機を複数保有し、原料や蒸溜方式、樽の組み合わせを細かく仕込み分けることで、実に多彩な個性を持つグレーン原酒を生み出す。長らくブレンデッドウイスキーを支える縁の下の力持ちとして目立たない存在だったが、近年は単独ボトルとしての評価も高まり、ハイボール需要の高まりとともに注目される蒸溜所となった。","bottles":["知多","知多 蒸溜所限定ボトル","響 ジャパニーズハーモニー(知多原酒使用)"],"trivia":"「知多」は日本では珍しいグレーンウイスキー単独銘柄として2015年に発売され、すっきりとした飲み口からハイボール用として若い世代にも高い人気を得ている。響やサントリーオールドなどのブレンド原酒としても長年活躍してきた縁の下の力持ちである。","tags":["chita","suntory","grain"]},{"id":"yoichi","name":"余市","en":"Yoichi","lat":43.2,"lon":140.77,"region":"japan","founded":1934,"history":"竹鶴政孝がスコットランドの気候風土に最も近い土地として選んだ北海道・余市に築いた、大日本果汁(後のニッカウヰスキー)発祥の蒸溜所。石炭を直接くべて蒸溜器を熱する石炭直火蒸溜という、火加減の調整が難しく手間のかかる伝統製法を今も守り続け、力強くスモーキーで骨太な原酒を生み出す。竹鶴夫妻ゆかりの旧邸宅も敷地内に残り、ニッカのルーツにして象徴的な存在である。","bottles":["余市シングルモルト","余市 ピーティー&ソルティ","余市 ウッディ&バニリック","竹鶴ピュアモルト"],"trivia":"竹鶴は当初、余市でリンゴジュース(後の大日本果汁=ニッカの社名の由来)を製造・販売して資金を稼ぎながら、ウイスキーの熟成が完了するのをじっと待ち続けたと伝わる。この苦労が今のニッカの礎となった。","tags":["yoichi","nikka","peated","coal-fired"]},{"id":"miyagikyo","name":"宮城峡","en":"Miyagikyo","lat":38.31,"lon":140.68,"region":"japan","founded":1969,"history":"竹鶴政孝が余市に次いで選んだ第二の蒸溜所で、仙台近郊、広瀬川と新川川が合流する霧深い渓谷にある。余市とは対照的に穏やかでフルーティーな原酒を生む土地として選定され、モルト用の単式蒸溜器に加えグレーン用の連続式蒸溜機も備える珍しい構成を持つ。竹鶴が晩年に手掛けた蒸溜所であり、ニッカのブレンドを支える味わいの多様性を一手に担っている。","bottles":["宮城峡シングルモルト","竹鶴17年","余市&宮城峡 ブレンデッド"],"trivia":"竹鶴は日本各地を探し歩いた末に、この渓谷の霧深い気候をスコットランドのハイランド地方になぞらえて建設地に選んだという。晩年の竹鶴が理想を追い求めて完成させた蒸溜所とも言われている。","tags":["miyagikyo","nikka","fruity"]},{"id":"fuji-gotemba","name":"富士御殿場","en":"Fuji Gotemba","lat":35.31,"lon":138.93,"region":"japan","founded":1973,"history":"富士山麓、御殿場に構えるキリンのウイスキー蒸溜所。単式蒸溜器・連続式蒸溜機・非加熱式連続蒸溜機を同一敷地内に併設し、モルトからグレーンまで一貫生産できる世界でも珍しい設備を持つ。富士山の伏流水と標高による冷涼な気候が、雑味の少ない繊細な原酒造りを支えており、自社原酒のみで完結したブレンドを組める希少な蒸溜所として知られている。","bottles":["富士山麓","富士 シングルグレーン","富士 シングルブレンデッド","陸"],"trivia":"同じ敷地内でモルト・グレーン双方を仕込めるため「富士」の名を冠したボトルはすべて自社原酒のみで完結したブレンドになっている。この一貫生産体制は世界のウイスキー蒸溜所の中でも珍しい特徴とされる。","tags":["fuji-gotemba","kirin","grain","single-site"]},{"id":"chichibu","name":"秩父","en":"Chichibu","lat":36.02,"lon":139.1,"region":"japan","founded":2008,"history":"実家の羽生蒸溜所廃業を経験した肥土伊知郎が、私財を投じて埼玉県秩父に一から築き上げた小規模蒸溜所。地元産のミズナラ樽やワインカスク樽など独自の樽仕込みに次々と挑戦し続け、世界的なクラフトウイスキーブームの波に乗って「イチローズモルト」の名で瞬く間に高い評価を獲得した。今では抽選でしか手に入らないほどの人気銘柄を数多く生み出している。","bottles":["イチローズモルト 秩父ザ・ファースト","イチローズモルト ダブルディスティラリーズ","秩父 ワインウッドリザーブ","秩父 オン・ザ・ウェイ"],"trivia":"肥土は廃業した羽生蒸溜所の原酒樽400本を自ら買い取って救出し、トランプのカードを模した「イチローズモルト カードシリーズ」として展開、世界のコレクターの間で高値で取引されるまでになった。","tags":["chichibu","ichiros-malt","craft","mizunara"]},{"id":"mars-shinshu","name":"マルス信州","en":"Mars Shinshu","lat":35.75,"lon":137.94,"region":"japan","founded":1985,"history":"本坊酒造が中央アルプス・木曽駒ヶ岳の麓、長野県宮田村に建てた標高798メートルの高地蒸溜所。日本で最も標高の高いウイスキー蒸溜所として知られ、年間を通じて冷涼な気候の中でゆっくりと熟成が進む。一時は稼働を休止していた時期もあったが、1985年に本格再稼働を果たし、現在は澄んだ空気と豊かな水源を活かした端正な原酒造りを続けている。","bottles":["マルス モルテージ 3&7","マルス モルテージ 越百","マルス ウイスキー ザ・シングルモルト 駒ヶ岳"],"trivia":"冷涼な気候による緩やかな熟成のため、他の蒸溜所に比べエンジェルズシェア(熟成中の蒸発によるロス)が少ないとされる。鹿児島の本社蔵とは対照的な高地の気候を生かした原酒造りが特徴である。","tags":["mars-shinshu","hombo-shuzo","highland","craft"]},{"id":"kanosuke","name":"嘉之助","en":"Kanosuke","lat":31.6,"lon":130.34,"region":"japan","founded":2017,"history":"鹿児島県日置市、東シナ海を望む土地に焼酎メーカーの小正醸造が建てた新しい蒸溜所。焼酎蔵として長年培ってきた蒸溜技術を生かしつつ、南国特有の高温多湿な気候の中で熟成のスピードを見極める挑戦を続けている。樽熟成焼酎「メロー・コヅル」を生んだ小正嘉之助の名を冠し、南九州発のジャパニーズウイスキーとして国内外の愛好家から注目を集める、勢いのある蒸溜所である。","bottles":["嘉之助 シングルモルト","嘉之助 蒸溜所限定","嘉之助 グレーンウイスキー"],"trivia":"鹿児島特有の高温多湿な気候により熟成が早く進むとされ、比較的若い年数の原酒でも複雑な味わいが生まれやすいという。蒸溜所は東シナ海を望む高台にあり、見学者向けの施設も充実している。","tags":["kanosuke","komasa-shuzo","kyushu","craft"]},{"id":"akkeshi","name":"厚岸","en":"Akkeshi","lat":43.05,"lon":144.85,"region":"japan","founded":2016,"history":"北海道東部、霧多布湿原にほど近い厚岸町に建てられた新興の蒸溜所。周辺で採れるピートを用いたピーテッドモルトを主体に、潮風とスモーキーな個性を持つスコットランド・アイラ島を思わせる原酒造りを目指して仕込みが行われている。二十四節気にちなんだシリーズ展開でも知られ、寒冷な気候とじっくりとした熟成を武器に世界的な評価を高めつつある蒸溜所である。","bottles":["厚岸 ブレンデッドウイスキー","厚岸 二十四節気シリーズ","厚岸 ニューポットピーテッド"],"trivia":"厚岸のピート採取地や冷涼な気候がスコットランド・アイラ島に似ていることから「日本のアイラ」を目指す蒸溜所として紹介されることが多い。地元産大麦の使用にもこだわり、地域一体のウイスキー造りを進めている。","tags":["akkeshi","peated","hokkaido","craft"]}]},{"id":"taiwan","name":"台湾","tagline":"専売の島から、世界最速熟成の産地へ","background":"台湾はかつて、ウイスキー造りには不向きとされた亜熱帯の島だった。日本統治時代の1922年、台湾総督府は酒類の製造と販売を専売局が独占する専売制度を敷き、戦後もこれを引き継いだ台湾省菸酒公売局(台湾たばこ酒公売局)のもとで、民間による酒類製造は長らく許されなかった。ウイスキーはあくまで輸入品を楽しむ文化にとどまっていた。\n\n転機は2002年に訪れる。台湾のWTO加盟に伴って酒税法が改正され、半世紀以上続いた専売制度は終わりを告げ、民間資本による酒類製造が解禁された。飲料大手・金車(King Car)グループはこの好機を逃さず、宜蘭県員山郷の山あいに蒸留所を建設する計画を打ち出す。\n\n2005年に着工、翌2006年から蒸留を開始した噶瑪蘭(Kavalan)蒸留所では、招かれたスコットランドの醸造化学者ジム・スワン博士が、シェリー樽の代替としてSTR(削り・再焼成・再チャー)樽を導入するなど、台湾の気候に適した独自の熟成理論を組み立てた。年間を通じて気温と湿度が高い亜熱帯の風土は、スコットランドの数倍とも言われる速さで原酒を熟成させる一方、樽から大量のエンジェルズシェアを奪っていくことも明らかになっていった。\n\n2008年、Kavalanは満を持して初のシングルモルトを世に送り出す。2010年には英国でのブラインドテイスティングでスコッチの名だたる銘柄を打ち破ったと伝わり業界を驚かせ、2015年にはワールド・ウイスキー・アワードでソリスト ヴィーニョ・バリークが世界最優秀シングルモルトに選ばれるなど、台湾は一躍ウイスキー新興国の代表格となった。\n\n同じ頃、かつての専売局を前身とする国営・台湾菸酒公司の南投酒廠も自社ブランド「OMAR(オマール)」でシングルモルト市場に参入した。専売の島は、いまや世界が熟成速度の実験場として注目する産地へと姿を変えている。","timeline":[{"year":1922,"era":"crisis","icon":"law","title":"専売制度の始まり","text":"日本統治下の台湾総督府が専売局を設立し、酒類の製造・販売を独占する専売制度を敷いた。"},{"year":1947,"era":"crisis","icon":"crown","title":"台湾省菸酒公売局","text":"戦後、国民政府が専売局を接収。台湾省菸酒公売局(台湾たばこ酒公売局)として専売体制を継続した。"},{"year":2002,"era":"renaissance","icon":"law","title":"WTO加盟と自由化","text":"台湾のWTO加盟に伴い酒税法が改正され、半世紀以上続いた酒類専売制度が終わり民間製造が解禁された。"},{"year":2005,"era":"renaissance","icon":"factory","title":"Kavalan蒸留所着工","text":"金車(King Car)グループが宜蘭県員山郷に蒸留所建設に着手。台湾初の民間ウイスキー蒸留所計画だった。"},{"year":2006,"era":"renaissance","icon":"still","title":"ジム・スワン博士とSTR樽","text":"蒸留を開始。招かれたジム・スワン博士がSTR樽など亜熱帯気候に適した独自の熟成手法を導入した。"},{"year":2008,"era":"renaissance","icon":"barrel","title":"初リリース","text":"Kavalanが台湾初のシングルモルトウイスキーを発売。専売終焉からわずか6年での市場投入だった。"},{"year":2009,"era":"renaissance","icon":"barrel","title":"亜熱帯熟成の発見","text":"高温多湿な気候により原酒が急速に熟成する一方、年間十数%にも及ぶ高いエンジェルズシェアが確認された。"},{"year":2010,"era":"renaissance","icon":"trophy","title":"スコッチを破る","text":"英国でのブラインドテイスティングでKavalanが著名なスコッチ銘柄を上回る評価を得たと伝わり、業界を驚かせた。"},{"year":2015,"era":"renaissance","icon":"trophy","title":"世界最優秀シングルモルト","text":"ワールド・ウイスキー・アワードでソリスト ヴィーニョ・バリークが世界最優秀シングルモルトに選出された。"},{"year":2015,"era":"renaissance","icon":"globe","title":"南投蒸留所OMARの台頭","text":"国営・台湾菸酒公司の南投酒廠が自社ブランド「OMAR」のシングルモルトを本格展開し、Kavalanに続く担い手として注目され始めた。"}],"distilleries":[{"id":"kavalan","name":"噶瑪蘭","en":"Kavalan","lat":24.68,"lon":121.71,"region":"taiwan","founded":2005,"history":"飲料大手・金車グループが2002年の酒類自由化を受けて2005年に宜蘭県員山郷に設立。翌2006年から蒸留を開始し、スコットランドの醸造化学者ジム・スワン博士の指導のもとSTR樽など独自の熟成技術を確立した。2008年に初リリースし、2010年代には国際的な品評会で数々の栄冠を手にし、台湾ウイスキーの名を世界に知らしめた台湾を代表する蒸留所である。","bottles":["カヴァラン クラシック","カヴァラン ソリスト ヴィーニョ・バリーク","カヴァラン コンサートマスター","カヴァラン ディスティラリーセレクト"],"trivia":"台湾には法定の最低熟成年数の定めがなく、亜熱帯気候ゆえ樽内で驚くほど速く熟成が進む。エンジェルズシェアは年間十数%に達するとも言われ、スコットランドの数倍の速さで原酒がまろやかになっていくという。","tags":["kavalan","str-cask","subtropical"]},{"id":"nantou","name":"南投","en":"Nantou (OMAR)","lat":23.91,"lon":120.68,"region":"taiwan","founded":1978,"history":"専売時代の国営酒造工場を前身とし、台湾菸酒公司(旧公売局)が運営する蒸留所。もともとブランデーや紹興酒などを手掛けていたが、Kavalanの成功に触発され自社ブランド「OMAR(オマール)」としてシングルモルト市場に参入した、と伝わる。南投県の内陸性の気候を活かし、Kavalanとは異なる樽構成の原酒造りに取り組んでいる。","bottles":["OMAR バーボンカスク","OMAR シェリーカスク","OMAR ピーテッドカスク"],"trivia":"かつて台湾唯一の酒類製造者だった専売局の流れを汲む国営企業が手がけるウイスキーであり、専売制の歴史とKavalan以降の民間自由化という台湾酒造りの二つの時代をつなぐ存在といえる。","tags":["nantou","omar","state-owned"]}]},{"id":"india","name":"インド","tagline":"灼熱が生む早熟の琥珀、世界最大のウイスキー市場からの挑戦状","background":"インドとウイスキーの縁は、19世紀の英領時代にさかのぼる。東インド会社とともに渡ってきた英国人たちは、故郷の酒を懐かしみ、やがて現地でも蒸留が行われるようになった。しかし独立後のインド市場で主流となったのは、大麦のモルトではなく、安価に大量生産できる糖蜜（廃糖蜜）を原料とした蒸留酒だった。これに少量のモルト原酒やフレーバーを加えたものが「インディアン・ウイスキー」として流通し、国内の巨大な人口を背景に、インドは気づけば世界最大のウイスキー消費国となっていた。\n\n流れが変わったのは1948年、バンガロールでアムルット・ディスティラリーズが創業したことに始まる。同社は数十年をかけて大麦モルトのみを原料とする本格的なシングルモルト造りに挑み、2004年、ついに「アムルット・シングルモルト」を英国グラスゴーの店頭に並べた。スコッチの本場に南インド産のモルトを問うという、当時としては大胆すぎる挑戦だった。\n\nその評価は思わぬ形で世界を駆け巡る。2010年、著名な評論家ジム・マレーが年鑑『ウイスキー・バイブル』において、アムルットの限定品「フュージョン」を世界第3位の傑出したウイスキーと評したのである。スコットランドでもアイルランドでもない土地から生まれた一本が、世界の頂点に迫った瞬間だった。\n\nインドのウイスキーづくりを語るうえで欠かせないのが、その気候である。バンガロールやゴアの熟成庫は年間を通じて高温多湿で、樽内の原酒とオークが激しく呼吸し合う。その結果、年間のエンジェルズシェア（熟成中の蒸発損失）は10%を優に超え、スコットランドの数倍の速さで熟成が進む。わずか数年の貯蔵でも、スコットランドの十数年物に匹敵する複雑な風味が生まれるといわれる。\n\nアムルットの成功に続き、ゴア州のポール・ジョンや北部ウッタル・プラデーシュ州のラムプールといった蒸留所が次々と国際市場に進出し、インディも新興ブランドとして名を挙げつつある。糖蜜ベースの大衆ウイスキーが国内市場を支え続ける一方で、大麦モルトによる高品質シングルモルトが世界の愛好家を驚かせ続けている。両者が併存する現在のインドは、ウイスキー地図における最も勢いのある新興産地のひとつである。","timeline":[{"year":1820,"era":"origins","icon":"ship","title":"英領時代の蒸留文化の伝来","text":"東インド会社とともに渡った英国人が望郷の酒を求め、インド亜大陸に西洋式蒸留の技術と嗜好が持ち込まれたと伝わる。"},{"year":1855,"era":"origins","icon":"factory","title":"初期蒸留所の設立","text":"北部の山岳地帯を中心に英国人技師の関与で蒸留所が開かれ、駐留する軍や行政官向けに酒が造られ始めた。"},{"year":1947,"era":"crisis","icon":"law","title":"インド独立と酒税制度の分立","text":"独立後、酒類課税が州ごとの管轄となり、原料や流通の規制が複雑化。安価な糖蜜原料への依存が強まる土壌となった。"},{"year":1948,"era":"crisis","icon":"factory","title":"アムルット・ディスティラリーズ創業","text":"バンガロールでジャグダレ家（創業者 R・N・ジャグダレ）により創業。当初は現地向けの蒸留酒生産から歩みを始めた。"},{"year":1982,"era":"crisis","icon":"glass","title":"糖蜜ベース「インディアン・ウイスキー」の隆盛","text":"廃糖蜜由来のニュートラルスピリッツに香味を加えた製品が国内市場を席巻し、世界最大級の消費量を支えた。"},{"year":1992,"era":"renaissance","icon":"still","title":"モルトウイスキー生産への本格投資","text":"アムルットが大麦モルトのみを原料とする本格シングルモルト造りへ舵を切り、設備刷新を進めたと伝わる。"},{"year":2004,"era":"renaissance","icon":"globe","title":"アムルット・シングルモルト、グラスゴーで発売","text":"スコッチの本場グラスゴーの店頭に南インド産シングルモルトが並び、業界に衝撃を与えた。"},{"year":2010,"era":"renaissance","icon":"trophy","title":"ジム・マレーが世界第3位と評価","text":"評論家ジム・マレーが年鑑でアムルット・フュージョンを絶賛し、インド産ウイスキーの実力を世界に知らしめた。"},{"year":2012,"era":"renaissance","icon":"factory","title":"ポール・ジョン、ゴアで本格始動","text":"ゴア州でポール・ジョン・ディスティラリーズがシングルモルト生産を拡大し、国際市場向け輸出を開始した。"},{"year":2016,"era":"renaissance","icon":"barrel","title":"ラムプールなど新興蒸留所の台頭","text":"北部ウッタル・プラデーシュ州のラムプールをはじめとする新興蒸留所が相次いで国際市場に進出し、インド産シングルモルトの裾野が広がり始めた。"}],"distilleries":[{"id":"amrut","name":"アムルット","en":"Amrut Distillery","lat":12.97,"lon":77.59,"region":"india","founded":1948,"history":"1948年にバンガロールで創業し、当初は現地向けの蒸留酒を手がけていた。1980年代以降、大麦モルトのみを原料とする本格シングルモルト造りへ転換し、2004年には英国グラスゴーで発売するという大胆な一手に出た。高温多湿な気候による急速な熟成を逆手に取り、独自の複雑な風味を確立。2010年にはジム・マレーが限定品「フュージョン」を世界第3位と評し、インド産ウイスキーの存在を世界に知らしめた立役者である。","bottles":["アムルット シングルモルト","アムルット フュージョン","アムルット カスク・ストレングス","アムルット ピーテッド"],"trivia":"バンガロールの標高約900メートルの土地でも熟成は非常に速く進み、わずか4〜5年の貯蔵でスコットランドの10年以上に匹敵する熟成感が生まれるといわれる。","tags":["amrut","fusion","high-altitude"]},{"id":"paul-john","name":"ポール・ジョン","en":"Paul John","lat":15.49,"lon":73.83,"region":"india","founded":1996,"history":"ゴア州の海沿いに拠点を構え、当初は地元向けの大衆向け蒸留酒やブランデー生産から始まった。2000年代以降にシングルモルト事業へ本格参入し、2012年から国際市場への輸出を拡大。ゴアの高温多湿な気候を活かした熟成と、インド産大麦を用いた原酒造りを特徴とし、ピーテッドタイプなど個性的なラインナップで評価を高めている。","bottles":["ポール・ジョン ブリリアンス","ポール・ジョン エディテッド","ポール・ジョン クラシック セレクト カスク","ポール・ジョン ニルヴァーナ"],"trivia":"ゴアの熱帯性気候ゆえエンジェルズシェアが年10%を超えることもあり、樽内の原酒は数年でスコットランドの倍以上の速さで色と風味を深めるとされる。","tags":["paul-john","goa","peated"]},{"id":"rampur","name":"ラムプール","en":"Rampur Indian Single Malt Whisky","lat":28.81,"lon":79.03,"region":"india","founded":1943,"history":"北部ウッタル・プラデーシュ州ラムプールに拠点を置く蒸留所で、母体の製糖・蒸留事業は1943年に始まったと伝わる。長らく国内向け蒸留酒の生産が中心だったが、2016年前後からヒマラヤ山麓の水と気候を活かしたシングルモルト事業に本格参入し、国際コンペティションでの受賞を重ねて新興インド産シングルモルトの一角として認知を広げている。","bottles":["ラムプール インディアン シングルモルト","ラムプール ダブルカスク","ラムプール PX シェリーカスク"],"trivia":"ヒマラヤ山脈に近い内陸の気候は寒暖差が大きく、同じインド産でも沿岸部のアムルットやポール・ジョンとは異なる熟成の進み方を見せるといわれる。","tags":["rampur","himalaya","single-malt"]}]},{"id":"australia","name":"オーストラリア","tagline":"150年の沈黙を破った、南半球のウイスキー革命","background":"オーストラリアへの入植が進んだ19世紀初頭、シドニーやヴァン・ディーメンズ・ランド(現タスマニア)には早くも余剰穀物を使った蒸留の営みがあった。移民たちが故郷から持ち込んだ技術で造られる酒は、辺境の暮らしを支える貴重な産物だったが、同時に穀物不足や治安の懸念も招いた。\n\n1838年、ヴァン・ディーメンズ・ランド総督ジョン・フランクリンは、食用に回すべき穀物が酒造りに消費されることを憂い、島内での蒸留を禁じる布告を出した。さらに1901年の連邦成立後には、蒸留器の最低容量を大型商業生産向けの規模に定める法律が敷かれ、小規模な蒸留所が営業する道はほぼ閉ざされてしまう。こうして タスマニアのウイスキーづくりは150年以上にわたり事実上の空白期を迎えることになった。\n\nこの長い沈黙を破ったのが、ホバートの測量士ビル・ラークである。1992年、彼は当局を粘り強く説得して蒸留免許を取得し、ラーク・ディスティラリーを開業した。これが現代オーストラリアン・ウイスキーの出発点とされる。翌々年にはサリバンズコーブも創業し、冷涼な気候と清冽な水を武器にタスマニア産ウイスキーが少しずつ評価を高めていった。\n\n2014年、サリバンズコーブのフレンチオーク・カスクがワールド・ウイスキー・アワードで世界最優秀シングルモルトに選ばれると、世界はこの島の実力に驚かされた。メルボルンのスターワードのようにオーストラリアワインの樽で熟成させる独自路線を打ち出す蒸留所も現れ、本土にもクラフト蒸留の波は広がっている。かつて禁じられていた土地は、今や個性豊かなウイスキー産地として世界の地図に刻まれている。","timeline":[{"year":1820,"era":"origins","icon":"ship","title":"植民地時代の蒸留","text":"入植者が持ち込んだ技術と余剰穀物により、シドニーやヴァン・ディーメンズ・ランドで小規模な蒸留が始まったと伝わる。"},{"year":1838,"era":"crisis","icon":"law","title":"蒸留禁止令","text":"ヴァン・ディーメンズ・ランド総督ジョン・フランクリンが、食用穀物確保を理由に島内での蒸留を禁止する布告を出した。"},{"year":1901,"era":"crisis","icon":"law","title":"連邦法による締め付け","text":"オーストラリア連邦成立後の蒸留法で最低蒸留器容量が大型化され、小規模蒸留所の新規参入は事実上不可能になった。"},{"year":1970,"era":"crisis","icon":"barrel","title":"続く空白期","text":"厳格な規制のもと、タスマニアでの合法な小規模ウイスキー蒸留は150年近く途絶えたままだったと伝わる。"},{"year":1992,"era":"renaissance","icon":"still","title":"ビル・ラーク、免許を取得","text":"測量士ビル・ラークが当局を説得して蒸留免許を取得し、ホバートにラーク・ディスティラリーを開業。現代タスマニア・ウイスキーの起点となった。"},{"year":1994,"era":"renaissance","icon":"barrel","title":"サリバンズコーブ創業","text":"ホバート近郊ケンブリッジでサリバンズコーブが創業。冷涼な気候を生かした熟成でタスマニア産ウイスキーの評価を高めていった。"},{"year":1999,"era":"renaissance","icon":"factory","title":"ヘリヤーズ・ロード誕生","text":"北岸バーニーの乳業会社が事業多角化として蒸留所を設立。大型ポットスチルによる生産で手に取りやすい価格のタスマニア産ウイスキーを送り出した。"},{"year":2004,"era":"renaissance","icon":"barrel","title":"スターワード始動","text":"メルボルンでデイヴィッド・ヴィターレがニュー・ワールド・ウイスキー・ディスティラリーを興し、後のスターワードにつながる、豪州ワイン樽での熟成という独自路線を打ち出した。"},{"year":2014,"era":"renaissance","icon":"trophy","title":"世界最優秀シングルモルトに輝く","text":"サリバンズコーブのフレンチオーク・カスクがワールド・ウイスキー・アワードで世界最優秀シングルモルトを受賞し、世界にタスマニアの名を轟かせた。"},{"year":2018,"era":"renaissance","icon":"globe","title":"豪州クラフトの拡大","text":"タスマニアだけでなくメルボルンなど本土でもクラフト蒸留所が相次いで誕生し、オーストラリアンウイスキーは世界市場での存在感を強めている。"}],"distilleries":[{"id":"lark","name":"ラーク","en":"Lark Distillery","lat":-42.88,"lon":147.33,"region":"australia","founded":1992,"history":"測量士のビル・ラークが1992年に免許を取得して開業した、現代オーストラリアン・ウイスキーの先駆け。ホバートの街なかに蒸留所とセラードアを構え、タスマニアの冷涼な気候と清冽な水を生かした小仕込みのシングルモルトを造り続けている。ラークの成功はその後に続く多くのタスマニア蒸留所の道を開いた。","bottles":["ラーク クラシック カスクストレングス","ラーク シングルカスク","ラーク ディスティラーズ・セレクション"],"trivia":"ビル・ラークが免許取得のきっかけを得たのは、川で釣りをしながらウイスキーづくりの可能性についてふと思い立ったから、と語られている。","tags":["lark","tasmania","hobart","renaissance"]},{"id":"sullivans-cove","name":"サリバンズコーブ","en":"Sullivans Cove","lat":-42.83,"lon":147.47,"region":"australia","founded":1994,"history":"1994年にホバート近郊ケンブリッジで創業。小規模仕込みとタスマニアの冷涼な熟成環境にこだわり、長年地道に品質を磨いてきた。2014年、フレンチオーク・カスクの一樽がワールド・ウイスキー・アワードで世界最優秀シングルモルトを受賞し、一躍世界にその名を知られることとなった。","bottles":["サリバンズコーブ フレンチオーク","サリバンズコーブ アメリカンオーク","サリバンズコーブ ダブルカスク"],"trivia":"世界最優秀に選ばれたフレンチオーク・カスクは、たった1樽分しか存在しない少量生産のシングルカスクだったと伝わる。","tags":["sullivans-cove","tasmania","cambridge","trophy"]},{"id":"starward","name":"スターワード","en":"Starward","lat":-37.81,"lon":144.96,"region":"australia","founded":2004,"history":"メルボルンでデイヴィッド・ヴィターレが興した蒸留所。タスマニアの蒸留所とは異なり、オーストラリア産の赤ワイン樽での熟成を軸とする独自路線を選び、地元産の大麦とメルボルンの寒暖差ある気候を生かした熟成で、若いうちから飲みごたえのあるスタイルを確立した。","bottles":["スターワード ノヴァ","スターワード ソレラ","スターワード トゥーフォールド"],"trivia":"赤ワイン樽での熟成にこだわるのは、メルボルン近郊のワイン産業と結びついた土地の個性を表現するためだと語られている。","tags":["starward","melbourne","wine-cask","renaissance"]},{"id":"hellyers-road","name":"ヘリヤーズ・ロード","en":"Hellyers Road","lat":-41.05,"lon":145.91,"region":"australia","founded":1999,"history":"タスマニア北岸バーニーの乳業協同組合が事業多角化の一環として1999年に設立した蒸留所。大型のポットスチルを備え、比較的まとまった量を生産できる体制を早くから整えたことで、他のタスマニア蒸留所に比べて手に取りやすい価格帯のシングルモルトを届けてきた。","bottles":["ヘリヤーズ・ロード オリジナル","ヘリヤーズ・ロード ピノノワール・フィニッシュ","ヘリヤーズ・ロード スライトリー・ピーテッド"],"trivia":"蒸留所名は、かつてこの地を測量した探検家ヘンリー・ヘリヤーにちなんで名付けられたと伝わる。","tags":["hellyers-road","tasmania","burnie","renaissance"]}]}]};
